// рҹҶ• v6.28.0: WhatsApp Business API вҖ” Server-seitiger Versand
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
let _whatsappConfig = null;
async function loadWhatsAppConfig() {
    if (_whatsappConfig !== null) return _whatsappConfig;
    try {
        const snap = await db.ref('settings/whatsapp').once('value');
        const cfg = snap.val() || {};
        _whatsappConfig = {
            enabled: cfg.enabled === true,
            apiToken: cfg.apiToken || null,
            phoneNumberId: cfg.phoneNumberId || null
        };
        return _whatsappConfig;
    } catch (e) {
        console.error('вқҢ WhatsApp-Config laden fehlgeschlagen:', e.message);
        return { enabled: false, apiToken: null, phoneNumberId: null };
    }
}

async function sendWhatsAppMessage(toPhone, text) {
    const config = await loadWhatsAppConfig();
    if (!config.enabled || !config.apiToken || !config.phoneNumberId) {
        return null; // WhatsApp nicht konfiguriert/aktiviert
    }

    // Telefonnummer formatieren (international ohne +)
    let formattedPhone = String(toPhone).replace(/[\s\-\/\(\)\+]/g, '');
    if (formattedPhone.startsWith('0')) {
        formattedPhone = '49' + formattedPhone.substring(1);
    }

    // Nur Mobilnummern (49-15xx, 49-16xx, 49-17xx) вҖ” auch leicht zu lange akzeptieren (KI-Tippfehler)
    if (!formattedPhone.match(/^49(1[5-7]\d{8,11})$/)) {
        console.log(`вҡ пёҸ WhatsApp: Keine Mobilnummer: ${formattedPhone}`);
        return null;
    }

    try {
        const resp = await fetch(`https://graph.facebook.com/v22.0/${config.phoneNumberId}/messages`, {
            method: 'POST',
            headers: {
                'Authorization': 'Bearer ' + config.apiToken,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                messaging_product: 'whatsapp',
                to: formattedPhone,
                type: 'text',
                text: { body: text }
            })
        });

        const data = await resp.json();
        if (resp.ok && data.messages && data.messages.length > 0) {
            console.log(`вң… WhatsApp gesendet an ${formattedPhone}: ${data.messages[0].id}`);
            return data.messages[0].id;
        } else {
            console.error('вқҢ WhatsApp Fehler:', JSON.stringify(data.error || data));
            return null;
        }
    } catch (e) {
        console.error('вқҢ WhatsApp Exception:', e.message);
        return null;
    }
}

// Hilfsfunktion: Kunden-Mobilnummer fГјr WhatsApp ermitteln
// рҹҶ• v6.34.2: WhatsApp wa.me Link fГјr Telegram-Nachrichten
function formatWhatsAppLink(phone) {
    if (!phone) return '';
    const clean = String(phone).replace(/[\s\-\/\(\)\+]/g, '');
    const normalized = clean.startsWith('0') ? '49' + clean.substring(1) : clean;
    // Nur fГјr Mobilnummern einen WA-Link erzeugen (auch leicht zu lange akzeptieren)
    if (normalized.match(/^49(1[5-7]\d{8,11})$/)) {
        return ` <a href="https://wa.me/${normalized}">рҹ’¬WA</a>`;
    }
    return '';
}

async function getCustomerWhatsAppNumber(ride) {
    // PrioritГӨt: mobilePhone > customerMobile > customerPhone > phone
    const candidates = [
        ride.mobilePhone,
        ride.customerMobile,
        ride.customerPhone,
        ride.phone
    ];

    for (const num of candidates) {
        if (!num) continue;
        const clean = String(num).replace(/[\s\-\/\(\)\+]/g, '');
        const normalized = clean.startsWith('0') ? '49' + clean.substring(1) : clean;
        // Nur Mobilnummern
        if (normalized.match(/^49(1[5-7]\d{8,9})$/)) return num;
    }

    // Fallback: CRM-Daten laden wenn customerId vorhanden
    if (ride.customerId) {
        try {
            const custSnap = await db.ref('customers/' + ride.customerId).once('value');
            const cust = custSnap.val();
            if (cust) {
                const crmCandidates = [cust.mobilePhone, cust.phone];
                for (const num of crmCandidates) {
                    if (!num) continue;
                    const clean = String(num).replace(/[\s\-\/\(\)\+]/g, '');
                    const normalized = clean.startsWith('0') ? '49' + clean.substring(1) : clean;
                    if (normalized.match(/^49(1[5-7]\d{8,9})$/)) return num;
                }
            }
        } catch (e) { /* ignore */ }
    }

    return null;
}

// WhatsApp-Kunden-Benachrichtigung senden (Text ohne HTML-Tags)
async function sendCustomerWhatsAppNotification(ride, rideId, type) {
    const phone = await getCustomerWhatsAppNumber(ride);
    if (!phone) return false;

    // рҹ”§ v6.36.0: Gastname hat PrioritГӨt Гјber Hotel/CRM-Name
    const passengerName = ride.guestName || ride.customerName;
    const greeting = passengerName ? `Hallo ${passengerName},\n\n` : '';

    const trackingLink = `https://umwelt-taxi-insel-usedom.de/Taxi-App/track.html?ride=${rideId}`;
    let message = '';

    if (type === 'booking_confirmed') {
        const driverInfo = ride.driverName ? `\nрҹ‘Ө Fahrer: ${ride.driverName}` : '';
        const vehicleInfo = ride.vehicle ? `\nрҹҡ— Fahrzeug: ${ride.vehicle}${ride.vehiclePlate ? ' (' + ride.vehiclePlate + ')' : ''}` : '';
        message = greeting +
            `рҹҡ• Ihr Taxi ist unterwegs!\n\n` +
            `рҹ“Қ Von: ${ride.pickup || '?'}\n` +
            `рҹҺҜ Nach: ${ride.destination || '?'}\n` +
            `рҹ•җ Abholung: ${ride.pickupTime || 'Sofort'}\n` +
            (ride.price ? `рҹ’° Preis: ca. ${ride.price}вӮ¬` : '') +
            driverInfo + vehicleInfo +
            `\n\nрҹ“І Fahrt live verfolgen:\n${trackingLink}\n\n` +
            `рҹ“һ Bei Fragen: 038378/22022`;

    } else if (type === 'booking_new') {
        message = greeting +
            `вң… Ihre Buchung wurde aufgenommen!\n\n` +
            `рҹ“Қ Von: ${ride.pickup || '?'}\n` +
            `рҹҺҜ Nach: ${ride.destination || '?'}\n` +
            `рҹ•җ Abholung: ${ride.pickupTime || 'Sofort'}\n` +
            (ride.price ? `рҹ’° Preis: ca. ${ride.price}вӮ¬` : '') +
            `\n\nвң… Sie erhalten Updates sobald ein Fahrer zugewiesen wird.\n\n` +
            `рҹ“һ Bei Fragen: 038378/22022`;

    } else if (type === 'cancelled') {
        message = greeting +
            `вқҢ Ihre Fahrt wurde storniert.\n\n` +
            `рҹ“Қ Von: ${ride.pickup || '?'}\n` +
            `рҹҺҜ Nach: ${ride.destination || '?'}\n\n` +
            `рҹ“һ Bei Fragen: 038378/22022`;

    } else if (type === 'driver_assigned') {
        const driverInfo = ride.driverName ? `\nрҹ‘Ө Fahrer: ${ride.driverName}` : '';
        const vehicleInfo = ride.vehicle ? `\nрҹҡ— Fahrzeug: ${ride.vehicle}${ride.vehiclePlate ? ' (' + ride.vehiclePlate + ')' : ''}` : '';
        // рҹҸ·пёҸ v6.40.13: "Vorgesehen" statt "Zugeteilt" (Fahrer hat noch nicht akzeptiert)
        message = greeting +
            `рҹҺҜ Fahrer vorgesehen!\n\n` +
            `рҹ“Қ Von: ${ride.pickup || '?'}\n` +
            `рҹҺҜ Nach: ${ride.destination || '?'}\n` +
            `рҹ•җ Abholung: ${ride.pickupTime || 'Sofort'}\n` +
            driverInfo + vehicleInfo +
            `\n\nрҹ“І Fahrt live verfolgen:\n${trackingLink}\n\n` +
            `рҹ“һ Bei Fragen: 038378/22022`;
    }

    if (!message) return false;

    const result = await sendWhatsAppMessage(phone, message);
    if (result) {
        console.log(`рҹ“ұ WhatsApp-Kunden-Nachricht (${type}) gesendet an: ${phone}`);
        await addTelegramLog('рҹ“ұ', 'whatsapp', `WhatsApp ${type}: ${passengerName || '?'}`, { rideId, phone });
    }
    return !!result;
}

