// рҹҶ• v6.11.3: SPRACHNACHRICHTEN вҖ“ Telegram Voice вҶ’ OpenAI Whisper вҶ’ Text
// Whisper API fГјr Transkription, dann Weiterverarbeitung als Textnachricht
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

async function getOpenAiApiKey() {
    const snap = await db.ref('settings/openai/apiKey').once('value');
    return snap.val() || null;
}

async function handleVoice(message) {
    const chatId = message.chat.id;
    const voice = message.voice;
    if (!voice || !voice.file_id) {
        await sendTelegramMessage(chatId, 'вҡ пёҸ Sprachnachricht konnte nicht verarbeitet werden.');
        return;
    }

    try {
        // 1. PrГјfe ob OpenAI API Key vorhanden
        const openaiKey = await getOpenAiApiKey();
        if (!openaiKey) {
            await addTelegramLog('вҡ пёҸ', chatId, 'Sprachnachricht empfangen, aber kein OpenAI API Key (settings/openai/apiKey)');
            await sendTelegramMessage(chatId, 'вҡ пёҸ Spracherkennung nicht konfiguriert.\nBitte schreiben Sie Ihre Anfrage als Text.');
            return;
        }

        // 2. Sende "Verarbeite..." Status
        await sendTelegramMessage(chatId, 'рҹҺҷпёҸ <i>Sprachnachricht wird verarbeitet...</i>');

        // 3. Hole Datei-Info von Telegram
        const token = await loadBotToken();
        const fileResp = await fetch(`https://api.telegram.org/bot${token}/getFile`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ file_id: voice.file_id })
        });
        const fileData = await fileResp.json();
        if (!fileData.ok || !fileData.result?.file_path) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Audio-Datei konnte nicht geladen werden.');
            return;
        }

        // 4. Lade die Audio-Datei herunter
        const fileUrl = `https://api.telegram.org/file/bot${token}/${fileData.result.file_path}`;
        const audioResp = await fetch(fileUrl);
        if (!audioResp.ok) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Audio-Download fehlgeschlagen.');
            return;
        }
        const audioBuffer = Buffer.from(await audioResp.arrayBuffer());

        // 5. Sende an OpenAI Whisper API zur Transkription
        // Whisper erwartet multipart/form-data mit der Audio-Datei
        const boundary = '----WhisperBoundary' + Date.now();
        const formParts = [];
        // model
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1`);
        // language (Deutsch)
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="language"\r\n\r\nde`);
        // prompt (Kontext fГјr bessere Erkennung)
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="prompt"\r\n\r\nTaxi-Buchung Usedom: Heringsdorf, Ahlbeck, Bansin, Zinnowitz, Koserow, Wolgast, SwinemГјnde, PeenemГјnde, Trassenheide, Karlshagen, Гңckeritz, Loddin, Zempin`);
        // file (Audio als OGG)
        const fileHeader = `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="voice.ogg"\r\nContent-Type: audio/ogg\r\n\r\n`;
        const fileFooter = `\r\n--${boundary}--\r\n`;

        // Baue den multipart Body zusammen
        const textParts = formParts.join('\r\n') + '\r\n';
        const textEncoder = new TextEncoder();
        const textBefore = textEncoder.encode(textParts + fileHeader);
        const textAfter = textEncoder.encode(fileFooter);

        const bodyBuffer = Buffer.concat([
            Buffer.from(textBefore),
            audioBuffer,
            Buffer.from(textAfter)
        ]);

        const transcribeResp = await fetch('https://api.openai.com/v1/audio/transcriptions', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${openaiKey}`,
                'Content-Type': `multipart/form-data; boundary=${boundary}`
            },
            body: bodyBuffer
        });

        if (!transcribeResp.ok) {
            const errData = await transcribeResp.json().catch(() => ({}));
            const errMsg = errData.error?.message || `HTTP ${transcribeResp.status}`;
            console.error('Whisper Transkription Fehler:', errMsg);
            await addTelegramLog('вқҢ', chatId, `Whisper Voice-Fehler: ${errMsg}`);
            await sendTelegramMessage(chatId, 'вҡ пёҸ Spracherkennung fehlgeschlagen. Bitte schreiben Sie Ihre Anfrage als Text.');
            return;
        }

        const transcribeResult = await transcribeResp.json();
        const transcript = (transcribeResult.text || '').trim();

        if (!transcript) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Konnte keine Sprache erkennen. Bitte sprechen Sie deutlicher oder schreiben Sie Ihre Anfrage.');
            return;
        }

        // 6. Zeige Transkript dem User
        await addTelegramLog('рҹҺҷпёҸ', chatId, `Sprachnachricht transkribiert: "${transcript}"`);
        await sendTelegramMessage(chatId, `рҹҺҷпёҸ <b>Erkannt:</b>\n<i>"${transcript}"</i>\n\nвҸі Wird verarbeitet...`);

        // 7. Verarbeite Transkript wie eine normale Textnachricht
        const fakeMessage = {
            ...message,
            text: transcript,
            _isVoiceTranscript: true
        };
        await handleMessage(fakeMessage);

    } catch (error) {
        console.error('handleVoice Fehler:', error);
        await addTelegramLog('вқҢ', chatId, `Voice-Fehler: ${error.message}`);
        await sendTelegramMessage(chatId, 'вҡ пёҸ Fehler bei der Sprachverarbeitung: ' + error.message + '\n\nBitte schreiben Sie Ihre Anfrage als Text.');
    }
}

// рҹҶ• v6.14.0: PrГјfe ob ein Dokument eine Audio-Datei ist
function isAudioDocument(doc) {
    if (!doc) return false;
    const mime = (doc.mime_type || '').toLowerCase();
    const name = (doc.file_name || '').toLowerCase();
    const audioMimes = ['audio/', 'video/ogg', 'application/ogg'];
    const audioExts = ['.mp3', '.wav', '.ogg', '.m4a', '.flac', '.aac', '.wma', '.opus', '.webm', '.mp4', '.3gp', '.amr'];
    if (audioMimes.some(m => mime.startsWith(m) || mime === m)) return true;
    if (audioExts.some(ext => name.endsWith(ext))) return true;
    return false;
}

// рҹҶ• v6.14.0: Audio-Dateien und Dokumente transkribieren (MP3, WAV, M4A etc.)
async function handleAudioFile(message) {
    const chatId = message.chat.id;
    // Audio kann als message.audio ODER message.document kommen
    const audioObj = message.audio || message.document;
    if (!audioObj || !audioObj.file_id) {
        await sendTelegramMessage(chatId, 'вҡ пёҸ Audio-Datei konnte nicht verarbeitet werden.');
        return;
    }

    const fileName = audioObj.file_name || audioObj.title || 'audio';
    const mimeType = audioObj.mime_type || 'audio/mpeg';
    const fileSize = audioObj.file_size || 0;

    // Telegram erlaubt max 20MB Download
    if (fileSize > 20 * 1024 * 1024) {
        await sendTelegramMessage(chatId, 'вҡ пёҸ Die Datei ist zu groГҹ (max. 20 MB). Bitte eine kГјrzere Aufnahme senden.');
        return;
    }

    try {
        // 1. OpenAI Key prГјfen
        const openaiKey = await getOpenAiApiKey();
        if (!openaiKey) {
            await addTelegramLog('вҡ пёҸ', chatId, `Audio-Datei empfangen (${fileName}), aber kein OpenAI API Key`);
            await sendTelegramMessage(chatId, 'вҡ пёҸ Spracherkennung nicht konfiguriert.\nBitte schreiben Sie Ihre Anfrage als Text.');
            return;
        }

        await sendTelegramMessage(chatId, `рҹҺҷпёҸ <i>Audio-Datei "${fileName}" wird transkribiert...</i>`);
        await addTelegramLog('рҹҺҷпёҸ', chatId, `Audio-Datei empfangen: ${fileName} (${(fileSize / 1024).toFixed(0)} KB, ${mimeType})`);

        // 2. Datei von Telegram herunterladen
        const token = await loadBotToken();
        const fileResp = await fetch(`https://api.telegram.org/bot${token}/getFile`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ file_id: audioObj.file_id })
        });
        const fileData = await fileResp.json();
        if (!fileData.ok || !fileData.result?.file_path) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Datei konnte nicht geladen werden.');
            return;
        }

        const fileUrl = `https://api.telegram.org/file/bot${token}/${fileData.result.file_path}`;
        const audioResp = await fetch(fileUrl);
        if (!audioResp.ok) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Audio-Download fehlgeschlagen.');
            return;
        }
        const audioBuffer = Buffer.from(await audioResp.arrayBuffer());

        // 3. An OpenAI Whisper senden
        // Dateiendung aus dem Dateinamen oder MIME-Type ableiten
        let ext = 'mp3';
        if (fileName.includes('.')) ext = fileName.split('.').pop().toLowerCase();
        else if (mimeType.includes('ogg')) ext = 'ogg';
        else if (mimeType.includes('wav')) ext = 'wav';
        else if (mimeType.includes('m4a') || mimeType.includes('mp4')) ext = 'm4a';
        else if (mimeType.includes('flac')) ext = 'flac';
        else if (mimeType.includes('webm')) ext = 'webm';

        const boundary = '----WhisperBoundary' + Date.now();
        const formParts = [];
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1`);
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="language"\r\n\r\nde`);
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="prompt"\r\n\r\nTaxi-Buchung Usedom: Heringsdorf, Ahlbeck, Bansin, Zinnowitz, Koserow, Wolgast, SwinemГјnde, PeenemГјnde, Trassenheide, Karlshagen, Гңckeritz, Loddin, Zempin`);

        const fileHeader = `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="audio.${ext}"\r\nContent-Type: ${mimeType}\r\n\r\n`;
        const fileFooter = `\r\n--${boundary}--\r\n`;

        const textParts = formParts.join('\r\n') + '\r\n';
        const textEncoder = new TextEncoder();
        const textBefore = textEncoder.encode(textParts + fileHeader);
        const textAfter = textEncoder.encode(fileFooter);

        const bodyBuffer = Buffer.concat([
            Buffer.from(textBefore),
            audioBuffer,
            Buffer.from(textAfter)
        ]);

        const transcribeResp = await fetch('https://api.openai.com/v1/audio/transcriptions', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${openaiKey}`,
                'Content-Type': `multipart/form-data; boundary=${boundary}`
            },
            body: bodyBuffer
        });

        if (!transcribeResp.ok) {
            const errData = await transcribeResp.json().catch(() => ({}));
            const errMsg = errData.error?.message || `HTTP ${transcribeResp.status}`;
            console.error('Whisper Audio-Datei Fehler:', errMsg);
            await addTelegramLog('вқҢ', chatId, `Whisper Audio-Fehler: ${errMsg}`);
            await sendTelegramMessage(chatId, 'вҡ пёҸ Transkription fehlgeschlagen: ' + errMsg + '\n\nBitte schreiben Sie Ihre Anfrage als Text.');
            return;
        }

        const transcribeResult = await transcribeResp.json();
        const transcript = (transcribeResult.text || '').trim();

        if (!transcript) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Konnte keine Sprache in der Datei erkennen. Ist die Aufnahme deutlich genug?');
            return;
        }

        await addTelegramLog('рҹҺҷпёҸ', chatId, `Audio-Datei transkribiert (${fileName}): "${transcript.substring(0, 100)}..."`);

        // рҹҶ• v6.14.8: TELEFONNUMMER AUS DATEINAMEN EXTRAHIEREN + CRM-SUCHE
        // Dateiname-Format 1 (alt): "+49_172_6324074_+491726324074_2026_03_10_09_33_20_Eingehend.m4a"
        // Dateiname-Format 2 (ACR): "+49 170 3522828 (+491703522828) [2026-03-31 15-38-32] [Eingehend].m4a"
        // oder: "Steigenberger_+4938378495901_2026_03_11_08_13_15_Eingehend.m4a"
        let callerPhone = null;
        let callerCustomer = null;
        // рҹ”§ v6.38.36: UnterstГјtzt ACR Phone Format mit Klammern + Leerzeichen
        // PrioritГӨt 1: Nummer in Klammern (+491703522828)
        const phoneParenMatch = fileName.match(/\((\+\d{10,15})\)/);
        // PrioritГӨt 2: Underscore-Format +49_172_6324074
        const phoneUnderscoreMatch = fileName.match(/\+(\d[\d_]{8,})(?=_20\d{2}_)/);
        // PrioritГӨt 3: Nummer mit Leerzeichen am Anfang +49 170 3522828
        const phoneSpaceMatch = fileName.match(/^\+(\d[\d ]{8,?\d})(?=\s*[\(\[])/);
        const phoneMatch = phoneParenMatch || phoneUnderscoreMatch || phoneSpaceMatch;
        if (phoneMatch) {
            callerPhone = phoneMatch[1].startsWith('+') ? phoneMatch[1] : '+' + phoneMatch[1].replace(/[_ ]/g, '');
            // рҹҶ• v6.25.1: Validierung der Anrufer-Nummer
            const callerValid = validatePhoneNumber(callerPhone);
            if (callerValid.valid) {
                await addTelegramLog('рҹ“һ', chatId, `Anrufer-Telefon aus Dateiname: ${callerPhone}`);
            } else {
                await addTelegramLog('вҡ пёҸ', chatId, `Anrufer-Telefon mГ¶glicherweise ungГјltig: ${callerPhone} вҖ” ${callerValid.warning}`);
            }

            // CRM-Suche nach dieser Telefonnummer (inkl. zusГӨtzliche Nummern bei Hotels)
            try {
                const allCust = await loadAllCustomers();
                const phoneDigits = callerPhone.replace(/\D/g, '');
                const last9 = phoneDigits.slice(-9);
                const foundCustomer = allCust.find(c => {
                    const p1 = (c.mobilePhone || '').replace(/\D/g, '');
                    const p2 = (c.phone || '').replace(/\D/g, '');
                    const p3 = (c.phone2 || '').replace(/\D/g, '');  // рҹ”§ v6.11.6: Zweite Festnetz-Nummer
                    if ((p1.length > 5 && p1.endsWith(last9)) ||
                        (p2.length > 5 && p2.endsWith(last9)) ||
                        (p3.length > 5 && p3.endsWith(last9))) return true;
                    // рҹҶ• v6.11.6: ZusГӨtzliche Telefonnummern prГјfen (z.B. Hotels mit mehreren Leitungen)
                    if (c.additionalPhones && Array.isArray(c.additionalPhones)) {
                        return c.additionalPhones.some(ap => {
                            const apDigits = (ap || '').replace(/\D/g, '');
                            return apDigits.length > 5 && apDigits.endsWith(last9);
                        });
                    }
                    return false;
                });
                if (foundCustomer) {
                    callerCustomer = foundCustomer;
                    await addTelegramLog('вң…', chatId, `Anrufer im CRM gefunden: ${foundCustomer.name} (${foundCustomer.customerId || foundCustomer.id})`);
                } else {
                    await addTelegramLog('рҹҶ•', chatId, `Anrufer ${callerPhone} nicht im CRM вҖ” Neukunde`);
                }
            } catch(e) {
                console.error('CRM-Suche fГјr Audio-Telefon fehlgeschlagen:', e.message);
            }
        }

        // Transkript + Anrufer-Info anzeigen
        let transcriptMsg = `рҹҺҷпёҸ <b>Transkript aus "${fileName}":</b>\n<i>"${transcript}"</i>`;
        if (callerCustomer) {
            const kindLabel = callerCustomer.customerKind === 'hotel' ? 'рҹҸЁ Hotel/Pension' : (callerCustomer.type === 'supplier' ? 'рҹҡҡ Lieferant' : (callerCustomer.customerKind === 'auftraggeber' ? 'рҹҸў Auftraggeber' : (callerCustomer.customerKind === 'gelegenheitskunde' ? 'рҹ§і Gelegenheitskunde' : 'рҹҸ  Stammkunde')));
            transcriptMsg += `\n\nрҹ‘Ө <b>Anrufer erkannt:</b> ${callerCustomer.name}`;
            transcriptMsg += `\n${kindLabel}`;
            if (callerCustomer.mobilePhone || callerCustomer.phone) transcriptMsg += `\nрҹ“ұ ${callerCustomer.mobilePhone || callerCustomer.phone}`;
            if (callerCustomer.address) transcriptMsg += `\n${callerCustomer.type === 'supplier' ? 'рҹҡҡ' : (isAuftraggeber(callerCustomer.customerKind, callerCustomer.type) ? 'рҹҸў' : (callerCustomer.customerKind === 'gelegenheitskunde' ? 'рҹ“Қ' : 'рҹҸ '))} ${callerCustomer.address}`;
        } else if (callerPhone) {
            transcriptMsg += `\n\nрҹ“һ <b>Anrufer:</b> ${callerPhone} (nicht im CRM)`;
        }
        transcriptMsg += '\n\nвҸі Wird verarbeitet...';
        await sendTelegramMessage(chatId, transcriptMsg);

        // Als normale Textnachricht weiterverarbeiten
        const fakeMessage = {
            ...message,
            text: transcript,
            _isVoiceTranscript: true,
            _isAudioFile: true,
            _callerPhone: callerPhone,
            _callerCustomer: callerCustomer
        };
        await handleMessage(fakeMessage);

    } catch (error) {
        console.error('handleAudioFile Fehler:', error);
        await addTelegramLog('вқҢ', chatId, `Audio-Datei Fehler: ${error.message}`);
        await sendTelegramMessage(chatId, 'вҡ пёҸ Fehler bei der Audio-Verarbeitung: ' + error.message);
    }
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹҶ• v6.38.0: FOTO/SCREENSHOT-HANDLER вҖ” Claude Vision OCR + Analyse
// Foto senden вҶ’ Text erkennen вҶ’ Termin oder CRM-Kontakt anlegen
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function _buildBookingText(booking) {
    if (!booking) return '';
    return [
        booking.datetime && `Zeit: ${booking.datetime}`,
        booking.name && `Name: ${booking.name}`,
        booking.phone && `Tel: ${booking.phone}`,
        booking.pickup && `Von: ${booking.pickup}`,
        booking.destination && `Nach: ${booking.destination}`,
        booking.passengers && booking.passengers > 1 && `Personen: ${booking.passengers}`,
        booking.notes && `Hinweis: ${booking.notes}`,
    ].filter(Boolean).join('\n');
}

async function handlePhoto(message) {
    const chatId = message.chat.id;
    const photos = message.photo;
    const caption = message.caption || '';

    if (!photos || photos.length === 0) {
        await sendTelegramMessage(chatId, 'вҡ пёҸ Bild konnte nicht verarbeitet werden.');
        return;
    }

    const isAdmin = await isTelegramAdmin(chatId);

    try {
        // 1. Anthropic API Key prГјfen
        const anthropicKey = await getAnthropicApiKey();
        if (!anthropicKey) {
            await addTelegramLog('вҡ пёҸ', chatId, 'Foto empfangen, aber kein Anthropic API Key');
            await sendTelegramMessage(chatId, 'вҡ пёҸ Bildanalyse nicht konfiguriert.\nBitte Anfrage als Text oder Sprachnachricht senden.');
            return;
        }

        await sendTelegramMessage(chatId, 'рҹ–јпёҸ <i>Screenshot wird analysiert...</i>');

        // 2. HГ¶chste AuflГ¶sung wГӨhlen (letztes Element = grГ¶Гҹtes Bild)
        const bestPhoto = photos[photos.length - 1];

        // 3. Datei von Telegram holen
        const token = await loadBotToken();
        const fileResp = await fetch(`https://api.telegram.org/bot${token}/getFile`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ file_id: bestPhoto.file_id })
        });
        const fileData = await fileResp.json();
        if (!fileData.ok || !fileData.result?.file_path) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Bild konnte nicht geladen werden.');
            return;
        }

        // 4. Bild herunterladen + Base64 konvertieren
        const fileUrl = `https://api.telegram.org/file/bot${token}/${fileData.result.file_path}`;
        const imgResp = await fetch(fileUrl);
        if (!imgResp.ok) {
            await sendTelegramMessage(chatId, 'вҡ пёҸ Bild-Download fehlgeschlagen.');
            return;
        }
        const base64 = Buffer.from(await imgResp.arrayBuffer()).toString('base64');
        const filePath = fileData.result.file_path || '';
        const mediaType = filePath.endsWith('.png') ? 'image/png' :
                          filePath.endsWith('.webp') ? 'image/webp' : 'image/jpeg';

        // 5. Claude Vision вҖ” Text + Typ erkennen
        const prompt = `Du bist ein Assistent fГјr ein Taxi-Unternehmen auf Usedom (Heringsdorf, Ahlbeck, Bansin, Zinnowitz, Wolgast).
${caption ? `Zusatz-Text des Senders: "${caption}"\n` : ''}
Analysiere dieses Bild. Lies ALLEN sichtbaren Text und bestimme ob es eine Buchung/Termin oder ein Kontakt ist.

Antworte NUR mit diesem JSON (kein anderer Text):
{
  "type": "booking" | "contact" | "both" | "unknown",
  "extractedText": "Gesamter sichtbarer Text aus dem Bild",
  "booking": {
    "name": null,
    "phone": null,
    "email": null,
    "pickup": null,
    "destination": null,
    "datetime": null,
    "passengers": 1,
    "notes": null
  },
  "contact": {
    "name": null,
    "phone": null,
    "mobile": null,
    "address": null,
    "email": null,
    "company": null,
    "notes": null
  },
  "confidence": "high" | "medium" | "low",
  "summary": "Kurze Zusammenfassung was erkannt wurde (1 Satz)"
}

Regeln:
- "booking": enthГӨlt Datum/Uhrzeit + Adresse/Ort (Taxi-Fahrt, Termin, BuchungsbestГӨtigung)
- "contact": enthГӨlt Name + Telefon/Adresse (Visitenkarte, Kontaktliste, WhatsApp-Profil)
- "both": beides erkennbar
- "unknown": keine verwertbaren Daten (Foto, Landschaft etc.)
- Unbekannte Felder als null lassen`;

        const visionResp = await callAnthropicAPI(anthropicKey, 'claude-haiku-4-5-20251001', 1024, [{
            role: 'user',
            content: [
                { type: 'image', source: { type: 'base64', media_type: mediaType, data: base64 } },
                { type: 'text', text: prompt }
            ]
        }]);

        const rawText = (visionResp.content?.[0]?.text || '').trim();
        await addTelegramLog('рҹ“·', chatId, `Foto-Analyse: ${rawText.substring(0, 120)}`);

        // 6. JSON parsen
        let analysis;
        try {
            const jsonMatch = rawText.match(/\{[\s\S]*\}/);
            analysis = JSON.parse(jsonMatch ? jsonMatch[0] : rawText);
        } catch (e) {
            // Fallback: Rohtext als Buchungstext verwenden
            await addTelegramLog('вҡ пёҸ', chatId, `Foto JSON-Fehler, Fallback auf Rohtext: ${e.message}`);
            if (rawText.length > 10) {
                await sendTelegramMessage(chatId, `рҹ“· <b>Text erkannt:</b>\n<i>"${rawText.substring(0, 300)}"</i>\n\nвҸі Wird als Buchung verarbeitet...`);
                const fakeMsg = { chat: { id: chatId }, from: message.from, text: rawText, _isPhotoTranscript: true };
                await handleMessage(fakeMsg);
            } else {
                await sendTelegramMessage(chatId, 'вҡ пёҸ Konnte keinen Text aus dem Bild lesen. Bitte bessere Beleuchtung oder schГӨrferes Bild versuchen.');
            }
            return;
        }

        const { type, extractedText, booking, contact, confidence, summary } = analysis;

        // 7. Wenn nichts erkannt
        if (type === 'unknown' || (!extractedText && !booking?.name && !contact?.name)) {
            await sendTelegramMessage(chatId, `рҹ–јпёҸ <b>Bild analysiert</b>\n\n${summary || 'Keine verwertbaren Informationen gefunden.'}\n\nрҹ’Ў Tipp: Screenshot von WhatsApp-Nachricht, Buchungsformular oder Visitenkarte senden.`);
            return;
        }

        // 8. Zusammenfassung aufbauen
        let infoMsg = `рҹ“· <b>Erkannt (${confidence || 'medium'}):</b> ${summary || type}\n\n`;
        if (type === 'booking' || type === 'both') {
            if (booking?.datetime) infoMsg += `рҹ•җ ${booking.datetime}\n`;
            if (booking?.name) infoMsg += `рҹ‘Ө ${booking.name}\n`;
            if (booking?.phone) infoMsg += `рҹ“ұ ${booking.phone}\n`;
            if (booking?.pickup) infoMsg += `рҹ“Қ Von: ${booking.pickup}\n`;
            if (booking?.destination) infoMsg += `рҹҺҜ Nach: ${booking.destination}\n`;
            if (booking?.passengers && booking.passengers > 1) infoMsg += `рҹ‘Ҙ ${booking.passengers} Personen\n`;
        }
        if (type === 'contact' || type === 'both') {
            if (contact?.name) infoMsg += `рҹ‘Ө ${contact.name}\n`;
            if (contact?.company) infoMsg += `рҹҸў ${contact.company}\n`;
            if (contact?.mobile) infoMsg += `рҹ“ұ ${contact.mobile}\n`;
            if (contact?.phone) infoMsg += `вҳҺпёҸ ${contact.phone}\n`;
            if (contact?.address) infoMsg += `рҹ“Қ ${contact.address}\n`;
            if (contact?.email) infoMsg += `вңүпёҸ ${contact.email}\n`;
        }
        infoMsg += '\nWas soll ich tun?';

        // 9. Inline-Buttons je nach Typ + Admin-Status
        const buttons = [];
        if (type === 'booking' || type === 'both') {
            buttons.push({ text: 'рҹ“Ӣ Als Buchung anlegen', callback_data: 'photo_action_booking' });
        }
        if ((type === 'contact' || type === 'both') && isAdmin) {
            buttons.push({ text: 'рҹ‘Ө Im CRM speichern', callback_data: 'photo_action_contact' });
        }
        if (type === 'unknown' || (!buttons.length && extractedText)) {
            buttons.push({ text: 'рҹ“Ӣ Als Buchung versuchen', callback_data: 'photo_action_booking' });
        }
        buttons.push({ text: 'вқҢ Abbrechen', callback_data: 'photo_action_cancel' });

        // 10. Analyse in Pending speichern (60 Minuten)
        await setPending(chatId, {
            _photoAnalysis: { type, extractedText, booking, contact, summary },
            _createdAt: Date.now()
        });

        await sendTelegramMessage(chatId, infoMsg, {
            reply_markup: { inline_keyboard: [buttons] }
        });

    } catch (error) {
        console.error('handlePhoto Fehler:', error);
        await addTelegramLog('вқҢ', chatId, `Foto-Fehler: ${error.message}`);
        await sendTelegramMessage(chatId, 'вҡ пёҸ Fehler bei der Bildanalyse: ' + error.message);
    }
}

async function handleLocation(message) {
    const chatId = message.chat.id;
    const lat = message.location.latitude;
    const lon = message.location.longitude;
    const userName = message.from?.first_name || 'Unbekannt';

    await addTelegramLog('рҹ“Қ', chatId, `GPS-Standort empfangen: ${lat.toFixed(5)}, ${lon.toFixed(5)}`);

    // Reverse-Geocoding: Koordinaten вҶ’ Adresse
    let addressName = `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
    const reversed = await reverseGeocode(lat, lon);
    // рҹ”§ v6.38.56: reverseGeocode gibt .name zurГјck (Duplikat-Version entfernt)
    if (reversed && reversed.name) {
        addressName = reversed.name;
        await addTelegramLog('рҹ“Қ', chatId, `Reverse-Geocoding: ${addressName}`);
    }

    // рҹҶ• v6.11.5: PrГјfe ob Neukunden-Adress-Schritt aktiv вҶ’ Standort als Kundenadresse Гјbernehmen
    const pending = await getPending(chatId);

    // рҹ”§ v6.26.0: Admin bearbeitet Fahrt-Adresse вҶ’ GPS direkt als neue Adresse Гјbernehmen
    if (pending && pending._adminEditRide && pending._adminEditField) {
        const rideId = pending._adminEditRide;
        const field = pending._adminEditField;
        const label = field === 'pickup' ? 'Abholort' : 'Zielort';
        await deletePending(chatId);
        await addTelegramLog('рҹ“Қ', chatId, `GPS als ${label} fГјr Fahrt ${rideId}: ${addressName}`);
        await applyAdminAddressChange(chatId, rideId, field, addressName, { lat, lon });
        return;
    }

    if (pending && pending._adminNewCust && (pending._adminNewCustStep === 'address' || pending._adminNewCustStep === 'address_select')) {
        await addTelegramLog('рҹ“Қ', chatId, `GPS-Standort als Kundenadresse: ${addressName} (${lat.toFixed(5)}, ${lon.toFixed(5)})`);

        // рҹ”§ v6.38.45: GPS = exakte Position. KEINE Nominatim-VorwГӨrtssuche!
        // Nur Reverse-Geocoding Adresse + nahegelegene CRM/Geocache-Adressen (< 200m)
        const GPS_RADIUS_KM = 0.2; // 200 Meter вҖ” GPS ist auf den Meter genau
        const nearbyAddresses = [];
        const seenAddrs = new Set();

        // Reverse-Geocoding Adresse als Hauptvorschlag
        nearbyAddresses.push({ name: addressName, lat, lon, source: 'gps-reverse' });
        seenAddrs.add(addressName.toLowerCase().trim());

        // Nur CRM-Kunden und Geocache im Umkreis von 200m prГјfen вҖ” KEIN Nominatim!
        try {
            const [geocacheSnap, custSnap] = await Promise.all([
                db.ref('geocache').once('value'),
                db.ref('customers').once('value')
            ]);
            // Geocache: gespeicherte Adressen in der NГӨhe
            if (geocacheSnap.exists()) {
                geocacheSnap.forEach(child => {
                    const e = child.val();
                    if (!e.address || !e.lat || !e.lon) return;
                    const dist = distanceKm(lat, lon, parseFloat(e.lat), parseFloat(e.lon));
                    if (dist <= GPS_RADIUS_KM && !seenAddrs.has(e.address.toLowerCase().trim())) {
                        seenAddrs.add(e.address.toLowerCase().trim());
                        nearbyAddresses.push({ name: e.address, lat: e.lat, lon: e.lon, source: 'geocache' });
                    }
                });
            }
            // CRM: Kunden-Adressen in der NГӨhe
            if (custSnap.exists()) {
                custSnap.forEach(child => {
                    const c = child.val();
                    if (!c.address || !c.lat || !c.lon) return;
                    const dist = distanceKm(lat, lon, parseFloat(c.lat), parseFloat(c.lon));
                    if (dist <= GPS_RADIUS_KM && !seenAddrs.has(c.address.toLowerCase().trim())) {
                        seenAddrs.add(c.address.toLowerCase().trim());
                        nearbyAddresses.push({ name: `${c.name}: ${c.address}`, lat: c.lat, lon: c.lon, source: 'customer' });
                    }
                });
            }
        } catch (e) { console.warn('GPS-Nearby-Suche Fehler:', e.message); }

        console.log(`рҹ“Қ GPS-AdressvorschlГӨge: ${nearbyAddresses.length} im Umkreis von ${GPS_RADIUS_KM * 1000}m`);
        const confirmId = Date.now().toString(36);

        if (nearbyAddresses.length > 1) {
            // Mehrere Adressen in der NГӨhe вҶ’ Auswahl anbieten
            const keyboard = nearbyAddresses.map((s, i) => [{ text: `${s.source === 'customer' ? 'рҹ‘Ө' : s.source === 'geocache' ? 'рҹ’ҫ' : 'рҹ“Қ'} ${s.name}`, callback_data: `admin_newcust_adr_${i}_${confirmId}` }]);
            keyboard.push([{ text: 'вңҸпёҸ Andere Adresse eingeben', callback_data: `admin_newcust_addr_retry_${confirmId}` }]);

            await setPending(chatId, {
                ...pending,
                _adminNewCustStep: 'address_select',
                _adminNewCustAddr: addressName,
                _adminNewCustAddrLat: lat,
                _adminNewCustAddrLon: lon,
                _adminNewCustSuggestions: nearbyAddresses,
                _addrConfirmId: confirmId
            });
            await sendTelegramMessage(chatId,
                `рҹ“Қ <b>GPS-Standort erkannt:</b>\nрҹҸ  ${addressName}\n\nBitte wГӨhle die richtige Adresse:`, {
                reply_markup: { inline_keyboard: keyboard }
            });
        } else {
            // Nur eine Adresse (die Reverse-Geocoding Adresse) вҶ’ direkt weiter zur Kundenart
            await setPending(chatId, {
                ...pending,
                _adminNewCustStep: 'customerKind',
                _adminNewCustAddr: addressName,
                _adminNewCustAddrLat: lat,
                _adminNewCustAddrLon: lon
            });
            await sendTelegramMessage(chatId,
                `рҹҸ·пёҸ <b>Kundenart festlegen</b>\n\nрҹ‘Ө <b>${pending._adminNewCustName}</b>\nрҹ“Қ ${addressName}\n\nIst das die <b>Wohnanschrift</b> oder nur eine <b>Abholadresse</b>?`, {
                reply_markup: { inline_keyboard: [
                    [{ text: 'рҹҸ  Wohnanschrift (Stammkunde)', callback_data: 'admin_newcust_kind_stamm' }],
                    [{ text: 'рҹ“Қ Nur Abholadresse (Gelegenheitskunde)', callback_data: 'admin_newcust_kind_gelegenheit' }],
                    [{ text: 'рҹҸЁ Hotel / Pension (bucht fГјr GГӨste)', callback_data: 'admin_newcust_kind_hotel' }],
                    [{ text: 'рҹҸў Firma (Klinik/bucht fГјr Andere)', callback_data: 'admin_newcust_kind_firma' }]
                ] }
            });
        }
        return;
    }

    // рҹ”§ v6.15.8: Laufende Buchung вҶ’ prГјfe was fehlt
    if (pending) {
        const booking = pending.booking || pending.partial;
        if (booking) {
            const missingPickup = !booking.pickup || (booking.missing && booking.missing.includes('pickup'));
            const missingDest = !booking.destination || (booking.missing && booking.missing.includes('destination'));

            // Nur Abholort fehlt вҶ’ direkt als Abholort setzen + Geocache-Frage
            if (missingPickup && !missingDest) {
                booking.pickup = addressName;
                booking.pickupLat = lat;
                booking.pickupLon = lon;
                if (booking.missing) booking.missing = booking.missing.filter(m => m !== 'pickup');
                await sendTelegramMessage(chatId, `рҹ“Қ <b>Abholort per GPS gesetzt:</b>\nрҹҸ  ${addressName}`);
                // рҹҶ• v6.38.15: Geocache-Frage stellen (pausiert Buchungsfluss bis Ja/Nein)
                const _gcUpdated = { ...pending, _awaitingGeocache: true, _geocacheLat: lat, _geocacheLon: lon, _geocacheAddr: addressName };
                if (pending.partial) _gcUpdated.partial = booking; else _gcUpdated.booking = booking;
                await setPending(chatId, _gcUpdated);
                await sendTelegramMessage(chatId,
                    `рҹ’ҫ <b>Adresse im Geocache speichern?</b>\nрҹ“Қ ${addressName}\n\n<i>Gespeicherte Adressen werden beim nГӨchsten Mal bevorzugt angezeigt.</i>`, {
                    reply_markup: { inline_keyboard: [
                        [{ text: 'вң… Ja, speichern', callback_data: `geocache_save_${lat.toFixed(5)}_${lon.toFixed(5)}` },
                         { text: 'вқҢ Nein', callback_data: 'geocache_skip' }]
                    ] }
                });
                return;
            }

            // Nur Zielort fehlt вҶ’ direkt als Zielort setzen + Geocache-Frage
            if (!missingPickup && missingDest) {
                booking.destination = addressName;
                booking.destinationLat = lat;
                booking.destinationLon = lon;
                if (booking.missing) booking.missing = booking.missing.filter(m => m !== 'destination');
                await sendTelegramMessage(chatId, `рҹ“Қ <b>Zielort per GPS gesetzt:</b>\nрҹҺҜ ${addressName}`);
                // рҹҶ• v6.38.15: Geocache-Frage stellen (pausiert Buchungsfluss bis Ja/Nein)
                const _gcUpdated2 = { ...pending, _awaitingGeocache: true, _geocacheLat: lat, _geocacheLon: lon, _geocacheAddr: addressName };
                if (pending.partial) _gcUpdated2.partial = booking; else _gcUpdated2.booking = booking;
                await setPending(chatId, _gcUpdated2);
                await sendTelegramMessage(chatId,
                    `рҹ’ҫ <b>Adresse im Geocache speichern?</b>\nрҹ“Қ ${addressName}\n\n<i>Gespeicherte Adressen werden beim nГӨchsten Mal bevorzugt angezeigt.</i>`, {
                    reply_markup: { inline_keyboard: [
                        [{ text: 'вң… Ja, speichern', callback_data: `geocache_save_${lat.toFixed(5)}_${lon.toFixed(5)}` },
                         { text: 'вқҢ Nein', callback_data: 'geocache_skip' }]
                    ] }
                });
                return;
            }

            // Beides fehlt oder beides schon da вҶ’ Fragen: Abholort oder Zielort?
            await setPending(chatId, {
                ...pending,
                _gpsChoice: { addressName, lat, lon }
            });
            await sendTelegramMessage(chatId,
                `рҹ“Қ <b>Standort empfangen:</b>\nрҹҸ  ${addressName}\n\nвқ“ <b>Ist das der Abholort oder der Zielort?</b>`, {
                reply_markup: { inline_keyboard: [
                    [{ text: 'рҹ“Қ Abholort', callback_data: 'gps_set_pickup' }, { text: 'рҹҺҜ Zielort', callback_data: 'gps_set_dest' }],
                    [{ text: 'вқҢ Abbrechen', callback_data: 'cancel_booking' }]
                ] }
            });
            return;
        }
    }

    // рҹ”§ v6.16.1: Neukunden-Anlage aktiv вҶ’ GPS als Kundenadresse behandeln (Race-Condition-Schutz)
    // Erneuter Check nГ¶tig, weil pending sich zwischen erstem Check und hier geГӨndert haben kann
    const pendingRecheck = await getPending(chatId);
    if (pendingRecheck && pendingRecheck._adminNewCust && (pendingRecheck._adminNewCustStep === 'address' || pendingRecheck._adminNewCustStep === 'address_select')) {
        await addTelegramLog('рҹ“Қ', chatId, `GPS-Standort als Kundenadresse Гјbernommen (Recheck): ${addressName}`);
        const confirmId = Date.now().toString(36);
        await setPending(chatId, {
            ...pendingRecheck,
            _adminNewCustStep: 'customerKind',
            _adminNewCustAddr: addressName,
            _adminNewCustAddrLat: lat,
            _adminNewCustAddrLon: lon
        });
        await sendTelegramMessage(chatId,
            `рҹҸ·пёҸ <b>Kundenart festlegen</b>\n\nрҹ‘Ө <b>${pendingRecheck._adminNewCustName}</b>\nрҹ“Қ ${addressName}\n\nIst das die <b>Wohnanschrift</b> oder nur eine <b>Abholadresse</b>?`, {
            reply_markup: { inline_keyboard: [
                [{ text: 'рҹҸ  Wohnanschrift (Stammkunde)', callback_data: 'admin_newcust_kind_stamm' }],
                [{ text: 'рҹ“Қ Nur Abholadresse (Gelegenheitskunde)', callback_data: 'admin_newcust_kind_gelegenheit' }],
                [{ text: 'рҹҸЁ Hotel/Pension', callback_data: 'admin_newcust_kind_hotel' }],
                [{ text: 'рҹҸў Auftraggeber/Firma', callback_data: 'admin_newcust_kind_auftraggeber' }]
            ] }
        });
        return;
    }

    // рҹ”§ v6.15.8: Kein laufender Buchungsvorgang вҶ’ Fragen ob Abhol- oder Zielort
    const customer = await getTelegramCustomer(chatId);
    const newBooking = {
        missing: ['pickup', 'destination', 'datetime'],
        intent: 'buchung'
    };
    if (customer) {
        newBooking.name = customer.name;
        newBooking.phone = customer.mobile || customer.phone || '';
    }

    await setPending(chatId, {
        partial: newBooking,
        originalText: `GPS: ${addressName}`,
        _gpsChoice: { addressName, lat, lon }
    });
    await sendTelegramMessage(chatId,
        `рҹ“Қ <b>Standort empfangen!</b>\nрҹҸ  ${addressName}\n\nвқ“ <b>Ist das der Abholort oder der Zielort?</b>`, {
        reply_markup: { inline_keyboard: [
            [{ text: 'рҹ“Қ Abholort (hier abholen)', callback_data: 'gps_set_pickup' }, { text: 'рҹҺҜ Zielort (dorthin fahren)', callback_data: 'gps_set_dest' }],
            [{ text: 'вқҢ Abbrechen', callback_data: 'cancel_booking' }]
        ] }
    });
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// WEBHOOK ENTRY POINT
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

exports.telegramWebhook = onRequest(
    { region: 'europe-west1', timeoutSeconds: 120, memory: '256MiB', minInstances: 1, invoker: 'public' },
    async (req, res) => {
        // рҹҶ• v6.25.5: Version in Firebase schreiben (fГјr App-Anzeige)
        // GET-Request вҶ’ Version zurГјckgeben (Health-Check)
        if (req.method === 'GET') {
            res.set('Access-Control-Allow-Origin', '*');
            res.json({ version: CLOUD_FUNCTIONS_VERSION, build: CLOUD_FUNCTIONS_BUILD, status: 'ok' });
            return;
        }
        // CORS fГјr OPTIONS (Preflight)
        if (req.method === 'OPTIONS') {
            res.set('Access-Control-Allow-Origin', '*');
            res.set('Access-Control-Allow-Methods', 'GET, POST');
            res.status(204).send('');
            return;
        }

        // Version beim ersten Aufruf in Firebase speichern
        try { await db.ref('settings/cloudFunctions').update({ version: CLOUD_FUNCTIONS_VERSION, build: CLOUD_FUNCTIONS_BUILD, lastActive: Date.now() }); } catch(e) {}

        // Nur POST akzeptieren
        if (req.method !== 'POST') {
            res.status(200).send('Funk Taxi Heringsdorf Telegram Bot - Webhook aktiv');
            return;
        }

        // Telegram-Webhook-Secret validieren (X-Telegram-Bot-Api-Secret-Token)
        const webhookSecret = await ensureWebhookSecret();
        const incomingToken = req.headers['x-telegram-bot-api-secret-token'];
        if (!incomingToken || incomingToken !== webhookSecret) {
            console.warn('Webhook: ungГјltiges oder fehlendes Secret-Token вҖ“ Anfrage abgelehnt');
            res.status(403).send('Forbidden');
            return;
        }

        // Tarif aus Firebase laden (einmalig pro Cold Start)
        await loadTarifFromFirebase();

        try {
            const update = req.body;

            // рҹ”§ v6.26.0: Kanal-Post erkennen (fГјr System-Kanal)
            if (update.channel_post) {
                // Ignorieren вҖ” Bot empfГӨngt eigene Posts im Kanal, kein Action nГ¶tig
                res.status(200).send('OK');
                return;
            }

            // рҹ”§ v6.26.0: Bot wurde zu Kanal/Gruppe hinzugefГјgt вҶ’ Channel-ID loggen
            if (update.my_chat_member) {
                const mcm = update.my_chat_member;
                const newStatus = mcm.new_chat_member?.status;
                const chatType = mcm.chat?.type;
                const channelChatId = mcm.chat?.id;
                const channelTitle = mcm.chat?.title || '?';
                if ((chatType === 'channel' || chatType === 'supergroup') && (newStatus === 'administrator' || newStatus === 'member')) {
                    console.log(`рҹ“ў Bot zu ${chatType} hinzugefГјgt: "${channelTitle}" (ID: ${channelChatId})`);
                    // Admins informieren mit der Kanal-ID zum einfachen Kopieren
                    try {
                        await sendToAllAdmins(
                            `рҹ“ў <b>Bot zu ${chatType === 'channel' ? 'Kanal' : 'Gruppe'} hinzugefГјgt!</b>\n\n` +
                            `рҹ“Ң <b>Name:</b> ${channelTitle}\n` +
                            `рҹҶ” <b>Chat-ID:</b> <code>${channelChatId}</code>\n\n` +
                            `рҹ’Ў Als System-Kanal setzen:\n<code>/setchannel ${channelChatId}</code>`
                        );
                    } catch (e) { /* non-critical */ }
                }
                res.status(200).send('OK');
                return;
            }

            // рҹӣЎпёҸ Spam-Schutz: chatId ermitteln
            const spamChatId = update.callback_query?.message?.chat?.id || update.message?.chat?.id;
            if (spamChatId) {
                // Zuerst prГјfen ob in Firebase dauerhaft geblockt
                if (!spamTracker[spamChatId]?.permBlocked) {
                    try {
                        const blockSnap = await db.ref(`settings/telegram/blockedUsers/${spamChatId}`).once('value');
                        if (blockSnap.val()) {
                            if (!spamTracker[spamChatId]) spamTracker[spamChatId] = { timestamps: [], blocked: false, blockedUntil: 0, warned: false, strikes: 0, permBlocked: true };
                            else spamTracker[spamChatId].permBlocked = true;
                        }
                    } catch(e) {}
                }

                const spamStatus = checkSpam(spamChatId);
                if (spamStatus === 'permblocked' || spamStatus === 'blocked') {
                    // Still ignorieren вҖ“ keine Antwort
                    res.status(200).send('OK');
                    return;
                }
                if (spamStatus === 'permblock_new') {
                    // Neuer permanenter Block вҶ’ in Firebase speichern + Admin benachrichtigen
                    const userName = update.message?.from?.first_name || update.callback_query?.from?.first_name || 'Unbekannt';
                    await addTelegramLog('рҹҡ«', spamChatId, `PERMANENT GEBLOCKT вҖ“ 3Г— Spam-Sperre (${userName})`);
                    await sendTelegramMessage(spamChatId,
                        'рҹҡ« <b>Ihr Zugang wurde gesperrt.</b>\n\n' +
                        'Sie haben wiederholt zu viele Nachrichten gesendet.\n' +
                        'Bitte kontaktieren Sie uns telefonisch: <b>038378 / 22022</b>'
                    );
                    // In Firebase speichern (Гјberlebt Cloud Function Restart)
                    try {
                        await db.ref(`settings/telegram/blockedUsers/${spamChatId}`).set({
                            blockedAt: Date.now(),
                            reason: '3x Spam-Sperre',
                            userName
                        });
                    } catch(e) {}
                    // Admins benachrichtigen
                    try {
                        const blockMsg = `рҹҡ« <b>Nutzer geblockt (Spam)</b>\n\nрҹ‘Ө ${userName}\nрҹҶ” Chat-ID: <code>${spamChatId}</code>\n\n<i>3Г— Spam-Limit Гјberschritten. Entblocken:\n/entblocken ${spamChatId}</i>`;
                        await sendToAllAdmins(blockMsg, 'spam_block');
                        await sendToSystemChannel(blockMsg, 'system');
                    } catch(e) {}
                    res.status(200).send('OK');
                    return;
                }
                if (spamStatus === 'spam') {
                    const tracker = spamTracker[spamChatId];
                    const remaining = SPAM_MAX_STRIKES - (tracker?.strikes || 0);
                    await addTelegramLog('рҹӣЎпёҸ', spamChatId, `SPAM erkannt вҖ“ 3 Min Sperre (Strike ${tracker?.strikes || '?'}/${SPAM_MAX_STRIKES})`);
                    await sendTelegramMessage(spamChatId,
                        'вҡ пёҸ <b>Zu viele Nachrichten!</b>\n\n' +
                        'Bitte warten Sie einen Moment, bevor Sie weitere Nachrichten senden.\n' +
                        `<i>Sperre wird in 3 Minuten aufgehoben.</i>\n\n` +
                        (remaining > 0 ? `вҡ пёҸ <b>Warnung:</b> Nach ${remaining} weiteren Sperre(n) wird Ihr Zugang dauerhaft gesperrt.` : '')
                    );
                    res.status(200).send('OK');
                    return;
                }
                if (spamStatus === 'warning') {
                    await sendTelegramMessage(spamChatId,
                        'вҸі <i>Bitte etwas langsamer вҖ“ ich bearbeite Ihre Anfragen nacheinander.</i>'
                    );
                }
            }

            if (update.callback_query) {
                await handleCallback(update.callback_query);
            } else if (update.message) {
                if (update.message.contact) {
                    await handleContact(update.message);
                } else if (update.message.location) {
                    await handleLocation(update.message);
                } else if (update.message.voice) {
                    // рҹҶ• v6.11.3: Sprachnachrichten transkribieren
                    await handleVoice(update.message);
                } else if (update.message.audio) {
                    // рҹҶ• v6.14.0: Audio-Dateien (MP3 etc.) transkribieren
                    await handleAudioFile(update.message);
                } else if (update.message.photo) {
                    // рҹҶ• v6.38.0: Fotos/Screenshots analysieren (Claude Vision)
                    await handlePhoto(update.message);
                } else if (update.message.document && isAudioDocument(update.message.document)) {
                    // рҹҶ• v6.14.0: Dokumente die Audio sind (WAV, M4A, OGG etc.)
                    await handleAudioFile(update.message);
                } else if (update.message.web_app_data) {
                    // рҹҶ• v6.16.2: Daten aus Telegram Web App (Datetime-Picker etc.)
                    await handleWebAppData(update.message);
                } else if (update.message.text) {
                    // рҹҶ• v6.41.91 / рҹ”§ v6.41.92: Claude-Bridge вҖ” Admin schickt /c oder /claude
                    // (Telegram-Slash-Befehl, im MenГј sichtbar) ODER als Prefix vor einem Text.
                    // Beispiel: '/c bug XY in CRM nachschauen' ODER '/claude noch was wichtiges'.
                    // Vorher gabs nur 'claude:' und 'c:' Prefixe вҖ” die wurden zu leicht versehentlich
                    // weggelassen oder auto-korrigiert. Slash-Befehl ist eindeutig.
                    const _bridgeText = update.message.text.trim();
                    // Slash-Command (mit oder ohne @botname): '/c' oder '/claude' am Anfang
                    // ODER alter Prefix-Stil 'claude:' / 'c:' (zur AbwГӨrtskompatibilitГӨt)
                    const _bridgeMatch = _bridgeText.match(/^(\/c(laude)?(@\w+)?|claude:|c:)\s*/i);
                    if (_bridgeMatch) {
                        const _bridgeChatId = update.message.from?.id || update.message.chat?.id;
                        if (await isTelegramAdmin(_bridgeChatId)) {
                            const _bridgeMsg = _bridgeText.slice(_bridgeMatch[0].length).trim();
                            const _bridgeTs = Date.now();
                            // Leere Nachrichten (nur '/c' ohne Text) вҶ’ Hilfetext statt Inbox-Push
                            if (!_bridgeMsg) {
                                try {
                                    await sendTelegramMessage(_bridgeChatId,
                                        `рҹ“Ҙ <b>Claude-Bridge</b>\n\n` +
                                        `Schick mir Notizen mit:\n` +
                                        `<code>/c bug XY in CRM</code>\n` +
                                        `<code>/claude lange Nachricht...</code>\n\n` +
                                        `Claude liest beim nГӨchsten "lies bridge" alles aus.`,
                                        { parse_mode: 'HTML' });
                                } catch(_) {}
                                res.status(200).send('OK');
                                return;
                            }
                            await db.ref(`claudeBridge/inbox/${_bridgeTs}`).set({
                                ts: _bridgeTs,
                                fromChatId: _bridgeChatId,
                                fromName: update.message.from?.first_name || update.message.from?.username || 'admin',
                                message: _bridgeMsg,
                                read: false,
                                source: 'telegram'
                            });
                            try {
                                await sendTelegramMessage(_bridgeChatId,
                                    `рҹ“Ҙ In Claude-Posteingang gepusht (#${_bridgeTs}).\n` +
                                    `Du kannst weitere Notizen senden вҖ” Claude liest beim nГӨchsten "lies bridge" alles aus.`);
                            } catch(_) {}
                            res.status(200).send('OK');
                            return;
                        }
                        // Kein Admin вҶ’ fГӨllt durch in normalen Handler (oder ignorieren)
                    }
                    await handleMessage(update.message);
                }
            }
        } catch (err) {
            // рҹ”§ v6.38.44: Zentrales Error-Logging statt nur console.error
            const _errChatId = update?.callback_query?.from?.id || update?.message?.from?.id || update?.message?.chat?.id || null;
            const _errContext = {
                chatId: _errChatId,
                severity: 'critical',
                data: {
                    updateType: update?.callback_query ? 'callback' : (update?.message?.text ? 'text' : (update?.message?.voice ? 'voice' : 'other')),
                    callbackData: update?.callback_query?.data?.substring(0, 100),
                    messageText: update?.message?.text?.substring(0, 100)
                }
            };
            // Pending-State fГјr Debugging holen
            if (_errChatId) {
                try {
                    const _errPending = await db.ref(`settings/telegram/pending/${_errChatId}`).once('value');
                    _errContext.pendingState = _errPending.val();
                } catch (e) { /* ignore */ }
            }
            await logError('telegramWebhook', err, _errContext);
        }

        // Immer 200 zurГјckgeben (sonst wiederholt Telegram den Request)
        res.status(200).send('OK');
    }
);

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// WEBHOOK SETUP HELPER (einmalig aufrufen per HTTP GET)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

exports.setupWebhook = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        const token = await loadBotToken();
        if (!token) {
            res.status(500).send('Kein Bot-Token in Firebase!');
            return;
        }

        // Webhook-URL = die URL dieser Cloud Function
        const projectId = process.env.GCLOUD_PROJECT || process.env.GCP_PROJECT || 'taxi-heringsdorf';
        const webhookUrl = `https://europe-west1-${projectId}.cloudfunctions.net/telegramWebhook`;

        // Secret automatisch generieren falls noch keins existiert
        const webhookSecret = await ensureWebhookSecret();

        try {
            const resp = await fetch(`https://api.telegram.org/bot${token}/setWebhook`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    url: webhookUrl,
                    allowed_updates: ['message', 'callback_query'],
                    drop_pending_updates: false,
                    secret_token: webhookSecret
                })
            });
            const data = await resp.json();

            if (data.ok) {
                // Webhook-Status in Firebase speichern
                await db.ref('settings/telegram/webhookActive').set(true);
                await db.ref('settings/telegram/webhookUrl').set(webhookUrl);
                await db.ref('settings/telegram/webhookSetAt').set(Date.now());
                await addTelegramLog('рҹҢҗ', 'system', `Webhook aktiviert: ${webhookUrl}`);
                res.status(200).send(`вң… Webhook gesetzt!\n\nURL: ${webhookUrl}\n\nDer Bot antwortet jetzt 24/7 вҖ“ auch ohne offenen Browser!`);
            } else {
                res.status(500).send(`вқҢ Webhook-Fehler: ${data.description}`);
            }
        } catch (e) {
            res.status(500).send(`вқҢ Fehler: ${e.message}`);
        }
    }
);

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// WEBHOOK DEAKTIVIEREN (zurГјck zu Browser-Polling)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

exports.removeWebhook = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        const token = await loadBotToken();
        if (!token) { res.status(500).send('Kein Bot-Token!'); return; }

        try {
            const resp = await fetch(`https://api.telegram.org/bot${token}/deleteWebhook`);
            const data = await resp.json();
            await db.ref('settings/telegram/webhookActive').set(false);
            await addTelegramLog('рҹҢҗ', 'system', 'Webhook deaktiviert вҶ’ Browser-Polling');
            res.status(200).send(data.ok ? 'вң… Webhook entfernt. Browser-Polling kann wieder starten.' : `вқҢ ${data.description}`);
        } catch (e) {
            res.status(500).send(`вқҢ Fehler: ${e.message}`);
        }
    }
);

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹҶ• v6.16.0: BOT-BEFEHLE REGISTRIEREN (setMyCommands)
// Registriert /menu als ersten Befehl im Telegram-MenГј
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

exports.setupBotCommands = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        const token = await loadBotToken();
        if (!token) { res.status(500).send('Kein Bot-Token!'); return; }

        try {
            const commands = [
                { command: 'menu', description: 'рҹҸ  HauptmenГј mit allen Funktionen' },
                { command: 'buchen', description: 'рҹҡ• Neue Fahrt buchen' },
                { command: 'status', description: 'рҹ“Ҡ Meine heutigen Fahrten' },
                { command: 'hilfe', description: 'в„№пёҸ Hilfe & Гңbersicht' },
                { command: 'abbrechen', description: 'вқҢ Aktuelle Buchung abbrechen' },
                { command: 'profil', description: 'рҹ‘Ө Mein Profil' },
                { command: 'abmelden', description: 'рҹ”“ Konto abmelden & Daten lГ¶schen' },
                { command: 'start', description: 'рҹ‘Ӣ Bot neu starten' },
                // рҹҶ• v6.41.92: Claude-Bridge Slash-Commands (fГјr Admins)
                { command: 'c', description: 'рҹӨ– Notiz an Claude (z.B. /c Bug XY)' },
                { command: 'claude', description: 'рҹӨ– Notiz an Claude (lange Form)' }
            ];

            const resp = await fetch(`https://api.telegram.org/bot${token}/setMyCommands`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ commands })
            });
            const data = await resp.json();
            await addTelegramLog('рҹ“Ӣ', 'system', 'Bot-Befehle registriert (setMyCommands)');
            res.status(200).send(data.ok ? 'вң… Bot-Befehle registriert! /menu ist jetzt im Telegram-MenГј.' : `вқҢ ${data.description}`);
        } catch (e) {
            res.status(500).send(`вқҢ Fehler: ${e.message}`);
        }
    }
);

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹҶ• v6.16.2: AUTOMATISCHE KONFLIKT-ERKENNUNG & UMPLANUNG
// LГӨuft alle 5 Minuten server-seitig вҖ” kein Browser nГ¶tig!
// Erkennt Zeitkonflikte (gleiches Fahrzeug, Гјberlappende Zeiten)
// und plant automatisch auf ein freies Fahrzeug um.
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

exports.autoResolveConflicts = onSchedule(
    {
        schedule: 'every 5 minutes',
        region: 'europe-west1',
        timeoutSeconds: 120,
        memory: '256MiB'
    },
    async (event) => {
        console.log('рҹ”„ Auto-Konflikt-PrГјfung gestartet...');

        try {
            // v6.47.2: KOSTEN-OPTIMIERUNG вҖ” vorher las diese Function ALLE rides bei jedem
            // Aufruf alle 5 Min (8.640x/Mo Г— 5MB = 43GB/Mo). Jetzt: nur Pickup-Timestamp
            // im Bereich [-2h, +24h] вҖ” Konflikte kГ¶nnen nur in diesem Fenster sein.
            const _now = Date.now();
            const _windowStart = _now - 2 * 60 * 60 * 1000;
            const _windowEnd = _now + 24 * 60 * 60 * 1000;
            const [ridesSnap, shiftsSnap, settingsSnap, prioritiesSnap, timeslotSnap] = await Promise.all([
                db.ref('rides').orderByChild('pickupTimestamp').startAt(_windowStart).endAt(_windowEnd).once('value'),
                db.ref('vehicleShifts').once('value'),
                db.ref('settings/pricing').once('value'),
                db.ref('settings/vehiclePriorities').once('value'),
                db.ref('settings/timeslotSettings').once('value')
            ]);

            const shiftsData = shiftsSnap.val() || {};
            const pricingSettings = settingsSnap.val() || {};
            const vehiclePriorities = prioritiesSnap.val() || {};
            const timeslotSettings = timeslotSnap.val() || {};
            // рҹ”§ v6.39.5: Soft/Hard Grenzen aus Einstellungen lesen
            const overlapSoftMin = timeslotSettings.overlapToleranceSoft || 5;
            const overlapHardMin = timeslotSettings.overlapToleranceHard || 10;
            console.log(`вҡҷпёҸ Overlap-Toleranz: Soft ${overlapSoftMin} Min, Hard ${overlapHardMin} Min`);
            const vorlaufMin = pricingSettings.autoOptimierungVorlaufMinuten || 60;
            const boardingTime = pricingSettings.boardingTime || 3;
            const alightingTime = pricingSettings.alightingTime || 2;
            const bufferMs = (boardingTime + alightingTime) * 60000;
            const mindestAbstandMs = (pricingSettings.mindestAbstandMin || 0) * 60000;
            const priorityAdvantageMin = pricingSettings.priorityAdvantageMinutes || 0;

            // рҹ”§ v6.25.4: Fahrzeug-PrioritГӨt aus Firebase (wie getVehiclePriority in index.html)
            const getVehiclePriority = (vehicleId) => {
                if (vehiclePriorities[vehicleId] !== undefined) return vehiclePriorities[vehicleId];
                return (OFFICIAL_VEHICLES[vehicleId] || {}).priority || 99;
            };

            // Alle aktiven zukГјnftigen Fahrten sammeln
            const now = Date.now();
            const allRides = [];
            const unassignedRides = [];
            ridesSnap.forEach(c => {
                const r = { ...c.val(), firebaseId: c.key };
                if (r.pickupTimestamp &&
                    r.pickupTimestamp > now + vorlaufMin * 60000 &&
                    !['deleted','cancelled','storniert','cancelled_pending_driver','completed'].includes(r.status) &&
                    !r.assignmentLocked) {
                    if (r.assignedVehicle) {
                        allRides.push(r);
                    } else {
                        unassignedRides.push(r);
                    }
                }
            });

            // рҹ”§ v6.25.4: PHASE -1 вҖ” Unzugewiesene Vorbestellungen zuweisen
            // Cloud Гјbernimmt jetzt die Zuweisung (Browser macht das nicht mehr)
            if (unassignedRides.length > 0) {
                console.log(`рҹҡ• Phase -1: ${unassignedRides.length} unzugewiesene Vorbestellung(en) zuweisen...`);
                for (const ride of unassignedRides) {
                    try {
                        const result = await autoAssignRide(ride.firebaseId, ride);
                        if (result && result.vehicleId) {
                            const vName = (OFFICIAL_VEHICLES[result.vehicleId] || {}).name || result.vehicleId;
                            console.log(`   вң… ${ride.customerName || '?'} вҶ’ ${vName} zugewiesen`);
                            // In allRides aufnehmen fГјr weitere Phasen
                            ride.assignedVehicle = result.vehicleId;
                            allRides.push(ride);
                        } else {
                            console.log(`   вҡ пёҸ ${ride.customerName || '?'} вҖ” kein Fahrzeug verfГјgbar`);
                        }
                    } catch(e) {
                        console.error(`   вқҢ Zuweisung fehlgeschlagen fГјr ${ride.firebaseId}:`, e.message);
                    }
                }
            }

            if (allRides.length === 0 && unassignedRides.length === 0) {
                console.log('вң… Keine relevanten Fahrten gefunden');
                return;
            }

            // Berlin-Zeitzone fГјr Datum
            const berlinDate = (ts) => {
                const d = new Date(ts);
                return d.toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' }); // YYYY-MM-DD
            };
            const berlinTime = (ts) => {
                const d = new Date(ts);
                return d.toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });
            };

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // рҹ”§ v6.38.34: PHASE -2 вҖ” ROUTENDATEN-GESUNDHEITSCHECK
            // Alle Fahrten ohne duration/distance вҶ’ nachberechnen + Admin warnen
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            const _allCheckRides = [...allRides, ...unassignedRides];
            const _missingRouteRides = _allCheckRides.filter(r => !r.duration && !r.estimatedDuration);
            if (_missingRouteRides.length > 0) {
                console.warn(`вҡ пёҸ Phase -2: ${_missingRouteRides.length} Fahrt(en) OHNE Routendaten!`);
                const _fixedRides = [];
                const _brokenRides = [];
                for (const ride of _missingRouteRides) {
                    if (ride.pickupLat && ride.destinationLat) {
                        try {
                            const _rr = await calculateTelegramRoutePrice({
                                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
                            });
                            if (_rr && _rr.duration) {
                                ride.duration = _rr.duration;
                                ride.estimatedDuration = _rr.duration;
                                ride.distance = _rr.distance;
                                ride.price = _rr.price;
                                await db.ref(`rides/${ride.firebaseId}`).update({
                                    duration: _rr.duration, estimatedDuration: _rr.duration,
                                    distance: _rr.distance, estimatedDistance: _rr.distance,
                                    price: _rr.price, estimatedPrice: _rr.price
                                });
                                _fixedRides.push(ride);
                                console.log(`   вң… ${ride.customerName || ride.firebaseId}: Route nachberechnet (${_rr.duration} min, ${_rr.distance} km)`);
                            } else {
                                _brokenRides.push(ride);
                                console.error(`   вқҢ ${ride.customerName || ride.firebaseId}: OSRM fehlgeschlagen`);
                            }
                        } catch (e) {
                            _brokenRides.push(ride);
                            console.error(`   вқҢ ${ride.customerName || ride.firebaseId}: Fehler: ${e.message}`);
                        }
                    } else {
                        _brokenRides.push(ride);
                        console.error(`   вқҢ ${ride.customerName || ride.firebaseId}: Keine Koordinaten!`);
                    }
                }
                // Admin Гјber ALLE problematischen Fahrten informieren
                if (_brokenRides.length > 0) {
                    const _brokenList = _brokenRides.map(r => {
                        const _t = r.pickupTimestamp ? berlinTime(r.pickupTimestamp) : '?';
                        const _d = r.pickupTimestamp ? berlinDate(r.pickupTimestamp) : '?';
                        const _hasCoords = r.pickupLat && r.destinationLat;
                        return `вҖў ${_d} ${_t} вҖ” ${r.customerName || '?'}: ${r.pickup || '?'} вҶ’ ${r.destination || '?'} ${_hasCoords ? '(OSRM fehlgeschlagen)' : '(Keine Koordinaten!)'}`;
                    }).join('\n');
                    await sendToAllAdmins(
                        `рҹҡЁ <b>ACHTUNG: ${_brokenRides.length} Fahrt(en) ohne Routendaten!</b>\n\n` +
                        `Diese Fahrten haben keine Dauer/Entfernung und kГ¶nnen NICHT korrekt eingeplant werden:\n\n` +
                        `${_brokenList}\n\n` +
                        `вқҢ <b>Konflikterkennung funktioniert NICHT fГјr diese Fahrten!</b>\n` +
                        `Bitte Adressen prГјfen und manuell korrigieren.`
                    );
                }
                if (_fixedRides.length > 0) {
                    console.log(`вң… Phase -2: ${_fixedRides.length} Fahrt(en) repariert, ${_brokenRides.length} problematisch`);
                }
            }

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // рҹҡҖ v6.26.0: PHASE 0 вҖ” SCHICHT-VALIDIERUNG
            // Fahrten auf Fahrzeugen ohne Dienst вҶ’ sofort umplanen
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            let totalShiftFixes = 0;
            const debugPhase0Lines = []; // Debug-Sammlung fГјr Telegram

            for (const ride of allRides) {
                if (['accepted', 'picked_up', 'on_way'].includes(ride.status)) {
                    debugPhase0Lines.push(`вҸӯпёҸ ${ride.customerName || '?'} вҖ” Гјbersprungen (Status: ${ride.status})`);
                    continue;
                }
                const rideDateStr = berlinDate(ride.pickupTimestamp);
                const rideTimeStr = berlinTime(ride.pickupTimestamp);

                const inShift = isVehicleInShift(ride.assignedVehicle, shiftsData, rideDateStr, rideTimeStr);
                const vName = (OFFICIAL_VEHICLES[ride.assignedVehicle] || {}).name || ride.assignedVehicle || '?';
                debugPhase0Lines.push(`${inShift ? 'вң…' : 'вқҢ'} ${rideDateStr} ${rideTimeStr} ${ride.customerName || '?'} вҶ’ ${vName} [${ride.status}] Schicht=${inShift}`);

                if (inShift) continue;

                // Fahrzeug hat keinen Dienst вҶ’ Alternative suchen
                const currInfo = OFFICIAL_VEHICLES[ride.assignedVehicle] || {};
                console.warn(`рҹ“… SCHICHT-PROBLEM: ${ride.customerName || '?'} (${rideTimeStr}) auf ${currInfo.name} вҖ” kein Dienst am ${rideDateStr}!`);

                const altVehicle = findAlternativeVehicle(
                    ride, ride.assignedVehicle, allRides, shiftsData, rideDateStr, pricingSettings, vehiclePriorities
                );

                if (!altVehicle) {
                    console.warn(`   вқҢ Kein alternatives Fahrzeug im Dienst fГјr ${ride.firebaseId}`);
                    debugPhase0Lines.push(`   вҶ’ вқҢ Keine Alternative gefunden!`);
                    // Debug: Warum kein Alternativfahrzeug?
                    for (const [vid, vI] of Object.entries(OFFICIAL_VEHICLES)) {
                        if (vid === ride.assignedVehicle) continue;
                        const altInShift = isVehicleInShift(vid, shiftsData, rideDateStr, rideTimeStr);
                        const cap = (vI.capacity || 4) >= (ride.passengers || 1);
                        debugPhase0Lines.push(`     ${vid}: Schicht=${altInShift}, KapazitГӨt=${cap}`);
                    }
                    continue;
                }

                const altInfo = OFFICIAL_VEHICLES[altVehicle] || {};
                console.log(`   вң… Schicht-Korrektur: ${ride.firebaseId} вҶ’ ${altInfo.name}`);
                debugPhase0Lines.push(`   вҶ’ вң… Umplanung: ${altInfo.name}`);

                await db.ref(`rides/${ride.firebaseId}`).update({
                    assignedVehicle: altVehicle,
                    vehicleId: altVehicle,
                    vehicle: altInfo.name || altVehicle,
                    vehicleLabel: altInfo.name || altVehicle,
                    vehiclePlate: altInfo.plate || '',
                    assignedVehicleName: altInfo.name || altVehicle,
                    assignedVehiclePlate: altInfo.plate || '',
                    assignedBy: 'cloud-auto-replan',
                    assignedAt: Date.now(),
                    updatedAt: Date.now(),
                    lastOptimizedAt: Date.now(),
                    lastOptimizedTo: altVehicle,
                    replanReason: `Schicht-Korrektur: ${currInfo.name} hat keinen Dienst am ${rideDateStr} um ${rideTimeStr}`
                });

                ride.assignedVehicle = altVehicle;
                totalShiftFixes++;

                try {
                    await db.ref('optimierungsLog').push({
                        timestamp: Date.now(),
                        type: 'cloud-replan-schicht',
                        rideId: ride.firebaseId,
                        vonVehicle: currInfo.name || ride.assignedVehicle,
                        zuVehicle: altInfo.name || altVehicle,
                        kunde: ride.customerName || '',
                        uhrzeit: rideTimeStr,
                        datum: rideDateStr,
                        grund: `Kein Dienst: ${currInfo.name}`
                    });
                } catch(e) { /* non-critical */ }

                try {
                    const msg = `рҹ“… *Schicht-Korrektur*\nрҹ“Ӣ ${ride.customerName || '?'} вҖў ${rideTimeStr}\nрҹ”„ ${currInfo.name} (kein Dienst) вҶ’ ${altInfo.name}`;
                    await sendToAllAdmins(msg, 'optimization');
                    await sendToSystemChannel(msg, 'optimization');
                } catch(e) { /* non-critical */ }
            }

            console.log(`вң… Phase 0 (Schicht): ${totalShiftFixes} Korrektur(en)`);

            // рҹ”§ Debug: Phase 0 Ergebnisse per Telegram senden (Гјber Firebase-Flag)
            try {
                const debugSnap2 = await db.ref('settings/debugOptimierung').once('value');
                if (debugSnap2.val() === true) {
                    const header = `рҹ”Қ *Debug: Phase 0 Schicht-Validierung*\nрҹ“Ҡ ${allRides.length} Fahrten, ${totalShiftFixes} Korrekturen\n\nSchichtdaten vorhanden fГјr: ${Object.keys(shiftsData).join(', ') || 'KEINE!'}\n`;
                    const debugMsg = header + '\n' + debugPhase0Lines.join('\n');
                    await sendToAllAdmins(debugMsg, 'optimization');
                    // рҹ”§ v6.34.0: Flag NICHT hier zurГјcksetzen вҖ” Phase 2 braucht ihn noch!
                }
            } catch(e) { /* non-critical */ }

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // PHASE 1 вҖ” ZEITKONFLIKT-AUFLГ–SUNG (bestehend)
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

            // Nach Fahrzeug + Datum gruppieren
            const byVehicleDate = {};
            for (const r of allRides) {
                const dateStr = berlinDate(r.pickupTimestamp);
                const key = `${r.assignedVehicle}|${dateStr}`;
                if (!byVehicleDate[key]) byVehicleDate[key] = [];
                byVehicleDate[key].push(r);
            }

            let totalReplanned = 0;

            for (const [key, vehicleRides] of Object.entries(byVehicleDate)) {
                if (vehicleRides.length < 2) continue;

                const [vehicleId, dateStr] = key.split('|');
                vehicleRides.sort((a, b) => a.pickupTimestamp - b.pickupTimestamp);

                // PrГјfe jedes aufeinanderfolgende Paar
                for (let i = 0; i < vehicleRides.length - 1; i++) {
                    const curr = vehicleRides[i];
                    const next = vehicleRides[i + 1];

                    // Fahrtdauer + Puffer
                    // рҹ”§ v6.38.34: Kein 20-Min-Fallback! Phase -2 hat Duration repariert, ansonsten 60 Min Sicherheit
                    const currDurMs = (curr.duration || curr.estimatedDuration || 60) * 60000;
                    const currEndMs = curr.pickupTimestamp + currDurMs + bufferMs;
                    const nextStartMs = next.pickupTimestamp;

                    // рҹҶ• v6.33.6: RГјckfahrt zur Basis + Anfahrt zum nГӨchsten Abholort einrechnen!
                    // Regel: Fahrer fГӨhrt nach JEDER Fahrt zurГјck zur Basis вҖ” AUSSER bei Anschlussfahrt.
                    // Anschlussfahrt = kurze Pause + Abholort nah am Zielort вҶ’ direkt weiter
                    let leerfahrtMs = 0;
                    let leerfahrtMin = 0;
                    let leerfahrtDetail = '';
                    const currDestLat = curr.destCoords?.lat || curr.destinationLat;
                    const currDestLon = curr.destCoords?.lon || curr.destinationLon;
                    const nextPickupLat = next.pickupCoords?.lat || next.pickupLat;
                    const nextPickupLon = next.pickupCoords?.lon || next.pickupLon;
                    const rideTimeStr = berlinTime(curr.pickupTimestamp);
                    const homeCoords = getVehicleHomeCoords(vehicleId, shiftsData, dateStr, rideTimeStr);

                    // Anschlussfahrt-Erkennung: Pause kurz + Abholort nah am Zielort
                    const afZeitfensterMin = pricingSettings.anschlussfahrtZeitfensterMin ?? 20;
                    const afRadiusKm = pricingSettings.anschlussfahrtRadiusKm ?? 5;
                    const gapMinutes = (nextStartMs - currEndMs) / 60000;
                    let destToPickupKm = 999;
                    if (currDestLat && currDestLon && nextPickupLat && nextPickupLon) {
                        destToPickupKm = gpsDistanceKm(currDestLat, currDestLon, nextPickupLat, nextPickupLon);
                    }
                    const isAnschlussfahrt = gapMinutes < afZeitfensterMin && destToPickupKm <= afRadiusKm;

                    if (currDestLat && currDestLon && nextPickupLat && nextPickupLon) {
                        try {
                            if (isAnschlussfahrt) {
                                // ANSCHLUSSFAHRT: Fahrer bleibt vor Ort вҶ’ Direktroute Ziel вҶ’ Abholort
                                const direktRoute = await calculateRoute(
                                    { lat: currDestLat, lon: currDestLon },
                                    { lat: nextPickupLat, lon: nextPickupLon }
                                );
                                if (direktRoute) {
                                    leerfahrtMin = direktRoute.duration;
                                    leerfahrtMs = leerfahrtMin * 60000;
                                    leerfahrtDetail = `${leerfahrtMin} Min direkt (Anschlussfahrt, ${destToPickupKm.toFixed(1)} km)`;
                                }
                            } else if (homeCoords?.lat && homeCoords?.lon) {
                                // STANDARD: Fahrer fГӨhrt zurГјck zur Basis вҶ’ dann zum nГӨchsten Abholort
                                const [rueckRoute, anfahrtRoute] = await Promise.all([
                                    calculateRoute(
                                        { lat: currDestLat, lon: currDestLon },
                                        { lat: homeCoords.lat, lon: homeCoords.lon }
                                    ),
                                    calculateRoute(
                                        { lat: homeCoords.lat, lon: homeCoords.lon },
                                        { lat: nextPickupLat, lon: nextPickupLon }
                                    )
                                ]);
                                const rueckMin = rueckRoute?.duration || 0;
                                const anfahrtMin = anfahrtRoute?.duration || 0;
                                leerfahrtMin = rueckMin + anfahrtMin;
                                leerfahrtMs = leerfahrtMin * 60000;
                                leerfahrtDetail = `${rueckMin} Min RГјckfahrt + ${anfahrtMin} Min Anfahrt`;
                            } else {
                                // Fallback: Direktroute (keine Basis hinterlegt)
                                const leerRoute = await calculateRoute(
                                    { lat: currDestLat, lon: currDestLon },
                                    { lat: nextPickupLat, lon: nextPickupLon }
                                );
                                if (leerRoute) {
                                    leerfahrtMin = leerRoute.duration;
                                    leerfahrtMs = leerfahrtMin * 60000;
                                    leerfahrtDetail = `${leerfahrtMin} Min direkt (keine Basis hinterlegt)`;
                                }
                            }
                        } catch(e) {
                            console.warn(`вҡ пёҸ Leerfahrt-Berechnung fehlgeschlagen:`, e.message);
                        }
                    }

                    // PrГјfung: Fahrtende + Leerfahrt + Mindestabstand > nГӨchste Abholzeit?
                    const earliestArrivalMs = currEndMs + leerfahrtMs + mindestAbstandMs;

                    // Gibt es Гңberlappung? (jetzt MIT Leerfahrt!)
                    if (earliestArrivalMs <= nextStartMs) continue; // Kein Konflikt

                    const overlapMin = Math.round((earliestArrivalMs - nextStartMs) / 60000);
                    const currTime = berlinTime(curr.pickupTimestamp);
                    const nextTime = berlinTime(next.pickupTimestamp);
                    const vName = OFFICIAL_VEHICLES[vehicleId]?.name || vehicleId;
                    const leerfahrtInfo = leerfahrtMin > 0 ? ` (inkl. ${leerfahrtDetail || leerfahrtMin + ' Min Leerfahrt'})` : '';

                    // рҹ”§ v6.39.5: Soft/Hard Grenzen anwenden
                    if (overlapMin <= overlapSoftMin) {
                        // Soft-Grenze: Tolerieren, nur loggen
                        console.log(`рҹҹЎ SOFT-KONFLIKT auf ${vName}: ${currTime} вҶ’ ${nextTime} вҖ” ${overlapMin} Min (Soft-Grenze: ${overlapSoftMin} Min) вҶ’ wird toleriert`);
                        continue;
                    }
                    if (overlapMin <= overlapHardMin) {
                        // Zwischen Soft und Hard: Warnung, aber nicht umplanen
                        console.warn(`рҹҹЎ KONFLIKT auf ${vName}: ${currTime} вҶ’ ${nextTime} вҖ” ${overlapMin} Min (Hard-Grenze: ${overlapHardMin} Min) вҶ’ Warnung, keine Umplanung`);
                        continue;
                    }

                    console.warn(`рҹ”ҙ HARD-KONFLIKT auf ${vName}: ${currTime} (${curr.customerName || '?'}) und ${nextTime} (${next.customerName || '?'}) вҖ” ${overlapMin} Min zu spГӨt${leerfahrtInfo} (Hard-Grenze: ${overlapHardMin} Min)`);

                    // Nicht umplanen wenn Fahrer bereits akzeptiert
                    if (['accepted', 'picked_up', 'on_way'].includes(next.status)) {
                        console.log(`   рҹҡ— ${next.firebaseId}: Status "${next.status}" вҶ’ keine Umplanung`);
                        continue;
                    }

                    // Alternatives Fahrzeug suchen
                    const altVehicle = findAlternativeVehicle(
                        next, vehicleId, allRides, shiftsData, dateStr, pricingSettings, vehiclePriorities
                    );

                    if (!altVehicle) {
                        console.warn(`   вқҢ Kein alternatives Fahrzeug fГјr ${next.firebaseId}`);
                        continue;
                    }

                    const altInfo = OFFICIAL_VEHICLES[altVehicle] || {};
                    console.log(`   вң… Umplanung: ${next.firebaseId} вҶ’ ${altInfo.name || altVehicle}`);

                    // In Firebase aktualisieren
                    await db.ref(`rides/${next.firebaseId}`).update({
                        assignedVehicle: altVehicle,
                        vehicleId: altVehicle,
                        vehicle: altInfo.name || altVehicle,
                        vehicleLabel: altInfo.name || altVehicle,
                        vehiclePlate: altInfo.plate || '',
                        assignedVehicleName: altInfo.name || altVehicle,
                        assignedVehiclePlate: altInfo.plate || '',
                        assignedBy: 'cloud-auto-replan',
                        assignedAt: Date.now(),
                        updatedAt: Date.now(),
                        lastOptimizedAt: Date.now(),
                        lastOptimizedTo: altVehicle,
                        replanReason: `Zeitkonflikt: ${overlapMin} Min zu spГӨt${leerfahrtInfo} nach ${curr.customerName || '?'} (${currTime}) auf ${vName}`
                    });

                    // Lokales Array aktualisieren (fГјr nГӨchste Paare)
                    next.assignedVehicle = altVehicle;
                    totalReplanned++;

                    // Log in Firebase fГјr Transparenz
                    try {
                        await db.ref('optimierungsLog').push({
                            timestamp: Date.now(),
                            type: 'cloud-replan',
                            rideId: next.firebaseId,
                            vonVehicle: vName,
                            zuVehicle: altInfo.name || altVehicle,
                            overlapMin,
                            kunde: next.customerName || '',
                            abholung: (next.pickup || '').substring(0, 50),
                            ziel: (next.destination || '').substring(0, 50),
                            uhrzeit: nextTime,
                            datum: dateStr,
                            grund: `Zeitkonflikt ${overlapMin} Min${leerfahrtInfo}`
                        });
                    } catch(e) { /* non-critical */ }

                    // рҹ”§ v6.30.1: Telegram-Benachrichtigung fГјr Konflikt-Umplanung
                    try {
                        const nextDateStr = berlinDate(next.pickupTimestamp);
                        const nextDateParts = nextDateStr.split('-');
                        const nextDateFmt = nextDateParts.length === 3 ? `${nextDateParts[2]}.${nextDateParts[1]}.` : nextDateStr;
                        const msg = `вҡ пёҸ *Zeitkonflikt-Umplanung*\nрҹ“… ${nextDateFmt} вҖў ${nextTime}\nрҹ“Ӣ ${next.customerName || '?'}\nрҹ”„ ${vName} вҶ’ ${altInfo.name || altVehicle}\nрҹ“Ң ${overlapMin} Min zu spГӨt${leerfahrtInfo} nach ${curr.customerName || '?'} (${currTime})`;
                        await sendToAllAdmins(msg, 'optimization');
                        await sendToSystemChannel(msg, 'optimization');
                    } catch(e) { /* non-critical */ }
                }
            }

            // рҹ”§ v6.39.5: PrГјfe ob cloud-auto-replan Fahrten auf dem ORIGINAL-Fahrzeug
            // besser aufgehoben wГӨren (z.B. nach Stornierung einer blockierenden Fahrt)
            // LГ¶sung: PrГјfe ob das ORIGINAL-Fahrzeug jetzt konfliktfrei wГӨre
            for (const ride of allRides) {
                if (ride.assignedBy !== 'cloud-auto-replan') continue;
                if (!ride.assignedVehicle || !ride.pickupTimestamp) continue;
                if (['accepted','picked_up','on_way','completed','deleted','cancelled','storniert'].includes(ride.status)) continue;

                // PrГјfe ALLE anderen Fahrzeuge ob eines besser wГӨre (kГјrzere Anfahrt, kein Konflikt)
                // рҹ”§ v6.41.93: Bug-Fix вҖ” Variable heiГҹt shiftsData, nicht vehicleShifts.
                // Seit 10 Tagen 887 ReferenceErrors, autoResolveConflicts hat NICHT gelaufen.
                let shouldRelease = false;
                for (const altVid of Object.keys(shiftsData || {})) {
                    if (altVid === ride.assignedVehicle) continue; // Aktuelles Гјberspringen
                    // Hat dieses Fahrzeug einen Konflikt mit der Fahrt?
                    const altRides = allRides.filter(r =>
                        (r.assignedVehicle === altVid) &&
                        r.id !== ride.id &&
                        !['completed','deleted','cancelled','storniert'].includes(r.status)
                    );
                    let altConflict = false;
                    for (const other of altRides) {
                        if (!other.pickupTimestamp) continue;
                        const dur1 = ride.duration || ride.estimatedDuration || 20;
                        const dur2 = other.duration || other.estimatedDuration || 20;
                        const end1 = ride.pickupTimestamp + (dur1 + 15) * 60000;
                        const end2 = other.pickupTimestamp + (dur2 + 15) * 60000;
                        if (ride.pickupTimestamp < end2 && other.pickupTimestamp < end1) {
                            altConflict = true;
                            break;
                        }
                    }
                    if (!altConflict) {
                        // Alternatives Fahrzeug ist konfliktfrei вҶ’ Optimierer soll prГјfen
                        shouldRelease = true;
                        break;
                    }
                }
                if (shouldRelease) {
                    const rideId = ride.firebaseId || ride.id;
                    await db.ref(`rides/${rideId}/assignedBy`).set('cloud-conflict-cleared');
                    console.log(`рҹ”“ ${ride.customerName}: Alternatives Fahrzeug konfliktfrei вҶ’ Optimierer darf prГјfen`);
                }
            }

            console.log(`вң… Phase 1 (Konflikte) abgeschlossen: ${totalReplanned} Umplanung(en)`);

            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
            // рҹҡҖ v6.26.0: PHASE 2 вҖ” LEERFAHRT-OPTIMIERUNG
            // Zentrale Umplanung: Fahrzeug mit kГјrzerer Anfahrt bevorzugen
            // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

            const minLeerfahrtVorteilMin = pricingSettings.optimierungMinVorteilMinuten || 10;
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehiclesData = vehiclesSnap.val() || {};
            let totalOptimized = 0;

            // Alle offenen, nicht akzeptierten Fahrten
            // рҹ”§ v6.39.5: Komplett ignorieren wenn von Konflikt-Umplanung zugewiesen
            // Ping-Pong Vermeidung: Optimierer plant NICHT um was Phase 1 zugewiesen hat
            // Wenn eine Stornierung Platz schafft, kГјmmert sich Phase 1 im nГӨchsten Lauf darum
            const optimizableRides = allRides.filter(r =>
                r.assignedVehicle &&
                !r.assignmentLocked &&
                !['accepted', 'picked_up', 'on_way', 'completed', 'deleted', 'cancelled', 'storniert'].includes(r.status) &&
                r.pickupTimestamp > now + vorlaufMin * 60000 &&
                r.assignedBy !== 'cloud-auto-replan' // Phase 1 Zuweisungen NIE anfassen
            );

            // рҹ”§ v6.25.4: Geocoding-Fallback вҖ” Fahrten ohne Koordinaten nachgeocoden
            for (const ride of optimizableRides) {
                if (!ride.pickupCoords && !ride.pickupLat) {
                    if (ride.pickup) {
                        try {
                            const geo = await geocode(ride.pickup);
                            if (geo && geo.lat && geo.lon) {
                                ride.pickupCoords = { lat: geo.lat, lon: geo.lon };
                                // Koordinaten auch in Firebase speichern fГјr nГӨchstes Mal
                                await db.ref(`rides/${ride.firebaseId}/pickupCoords`).set({ lat: geo.lat, lon: geo.lon });
                                console.log(`рҹ“Қ Geocoding-Fallback: ${ride.customerName || '?'} вҶ’ ${ride.pickup} вҶ’ ${geo.lat},${geo.lon}`);
                            }
                        } catch(e) { /* non-critical */ }
                    }
                }
            }

            console.log(`рҹҡҖ Phase 2 (Optimierung): ${optimizableRides.length} Fahrten prГјfen (Mindest-Vorteil: ${minLeerfahrtVorteilMin} Min, Prio-Vorteil: ${priorityAdvantageMin} Min)...`);

            // рҹ”§ v6.34.0: Debug-Log fГјr Phase 2
            const debugPhase2Lines = [];

            for (const ride of optimizableRides) {
                const currentVehicle = ride.assignedVehicle;
                const pickupLat = ride.pickupCoords?.lat || ride.pickupLat;
                const pickupLon = ride.pickupCoords?.lon || ride.pickupLon;
                if (!pickupLat || !pickupLon) {
                    debugPhase2Lines.push(`вҸӯпёҸ ${ride.customerName || '?'} вҖ” keine Koordinaten`);
                    continue;
                }

                const dateStr = berlinDate(ride.pickupTimestamp);
                const timeStr = berlinTime(ride.pickupTimestamp);

                // рҹ”§ v6.25.4: Smart Routing via OSRM вҖ” echte Fahrzeiten statt Luftlinie
                const currentResult = await estimateVehicleLeerfahrt(
                    currentVehicle, ride, allRides, vehiclesData, shiftsData, dateStr, pricingSettings
                );
                const currentMin = currentResult.durationMin;
                const currentKm = currentResult.distKm;

                // рҹ”§ v6.25.4: PrioritГӨts-Penalty wie autoAssignVehicleToRide (index.html Zeile 30593-30594)
                const currentPrio = getVehiclePriority(currentVehicle);
                // рҹҶ• v6.32.0: Lastverteilung in Phase 2
                const lastverteilungMalus = pricingSettings.lastverteilungMalusMinuten || 3;
                const currentRideCount = allRides.filter(r => r.assignedVehicle === currentVehicle && r.firebaseId !== ride.firebaseId).length;
                const totalActiveVehicles = Object.keys(OFFICIAL_VEHICLES).filter(vid => isVehicleInShift(vid, shiftsData, dateStr, timeStr)).length || 1;
                const avgRidesPerVehicle = optimizableRides.length / totalActiveVehicles;
                const currentLoadPenalty = currentRideCount > avgRidesPerVehicle ? Math.round((currentRideCount - avgRidesPerVehicle) * lastverteilungMalus) : 0;
                const currentScore = currentMin + (currentPrio - 1) * priorityAdvantageMin + currentLoadPenalty;

                // Beste Alternative suchen
                let bestAlt = null;
                let bestScore = currentScore;
                let bestMin = currentMin;
                let bestKm = currentKm;
                let bestMethod = currentResult.method;

                const candidates = Object.entries(OFFICIAL_VEHICLES)
                    .filter(([vid]) => vid !== currentVehicle)
                    .sort((a, b) => getVehiclePriority(a[0]) - getVehiclePriority(b[0]));

                // рҹ”§ v6.34.0: Debug-Infos pro Kandidat sammeln
                const candidateDebug = [];

                for (const [vehicleId, vInfo] of candidates) {
                    const vName = vInfo.name || vehicleId;
                    // KapazitГӨt
                    if ((vInfo.capacity || 4) < (ride.passengers || 1)) {
                        candidateDebug.push(`  ${vName}: вқҢ KapazitГӨt ${vInfo.capacity} < ${ride.passengers}`);
                        continue;
                    }
                    // Schichtplan
                    if (!isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr)) {
                        candidateDebug.push(`  ${vName}: вқҢ Kein Dienst`);
                        continue;
                    }

                    // рҹҶ• v6.26.0: Schichtende-PrГјfung
                    const _cRideDurMin = ride.duration || ride.estimatedDuration || 20;
                    const _cRideEndMs = ride.pickupTimestamp + _cRideDurMin * 60000;
                    const _cRideEndBerlin = new Date(new Date(_cRideEndMs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                    const _cRideEndTimeStr = String(_cRideEndBerlin.getHours()).padStart(2,'0') + ':' + String(_cRideEndBerlin.getMinutes()).padStart(2,'0');
                    const _cShiftEnd = getShiftEndTime(vehicleId, shiftsData, dateStr, timeStr);
                    if (_cShiftEnd && _cRideEndTimeStr > _cShiftEnd) {
                        candidateDebug.push(`  ${vName}: вқҢ Schichtende ${_cShiftEnd} < Fahrtende ${_cRideEndTimeStr}`);
                        continue;
                    }

                    // рҹ”§ v6.26.0: Besetzt-Check вҖ” Fahrzeug darf nicht aktiv unterwegs sein!
                    // рҹ”§ v6.34.0: FIX вҖ” 'assigned' entfernt! Vorbestellung im Juli darf
                    // nicht Fahrzeug heute blockieren. Nur on_way/picked_up = wirklich unterwegs.
                    const busyRide = allRides.find(r =>
                        (r.vehicleId === vehicleId || r.assignedVehicle === vehicleId) &&
                        (r.status === 'on_way' || r.status === 'picked_up') &&
                        r.firebaseId !== ride.firebaseId
                    );
                    if (busyRide) {
                        candidateDebug.push(`  ${vName}: вқҢ Besetzt (${busyRide.customerName || '?'}, Status: ${busyRide.status})`);
                        continue;
                    }

                    // рҹ”§ v6.39.5: Zeitkonflikt MIT Leerfahrt prГјfen (wie Phase 1!)
                    // Nicht nur Гңberlappung, sondern: schafft der Fahrer es rechtzeitig?
                    const rideDurMs = (ride.duration || ride.estimatedDuration || 20) * 60000;
                    const vehicleRidesForConflict = allRides.filter(r =>
                        r.assignedVehicle === vehicleId &&
                        r.firebaseId !== ride.firebaseId &&
                        r.pickupTimestamp &&
                        !['deleted','cancelled','storniert','completed'].includes(r.status)
                    );
                    // рҹ”§ v6.39.5: Leerfahrt aus Koordinaten berechnen (Haversine)
                    function quickLeerfahrtMin(fromLat, fromLon, toLat, toLon) {
                        if (!fromLat || !fromLon || !toLat || !toLon) return 10; // Fallback 10 Min
                        const dLat = (fromLat - toLat) * Math.PI / 180;
                        const dLon = (fromLon - toLon) * Math.PI / 180;
                        const a = Math.sin(dLat/2)**2 + Math.cos(fromLat*Math.PI/180)*Math.cos(toLat*Math.PI/180)*Math.sin(dLon/2)**2;
                        const distKm = 6371 * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
                        return Math.max(2, Math.round(distKm * 1.3 / 40 * 60)); // 40 km/h Durchschnitt
                    }

                    let hasConflict = false;
                    let conflictRideName = '';
                    for (const r of vehicleRidesForConflict) {
                        const rDurMs = (r.duration || r.estimatedDuration || 20) * 60000;
                        if (r.pickupTimestamp < ride.pickupTimestamp) {
                            // r ist VOR der neuen Fahrt вҖ” schafft Fahrer es rechtzeitig?
                            const rEndMs = r.pickupTimestamp + rDurMs + bufferMs;
                            // Echte Leerfahrt: r-Zielort вҶ’ ride-Abholort
                            const rDestLat = r.destCoords?.lat || r.destinationLat;
                            const rDestLon = r.destCoords?.lon || r.destinationLon;
                            const ridePLat = ride.pickupCoords?.lat || ride.pickupLat;
                            const ridePLon = ride.pickupCoords?.lon || ride.pickupLon;
                            const leerfahrtMin = quickLeerfahrtMin(rDestLat, rDestLon, ridePLat, ridePLon);
                            const leerfahrtMs = leerfahrtMin * 60000;
                            if (rEndMs + leerfahrtMs > ride.pickupTimestamp) {
                                const zuSpaetMin = Math.round((rEndMs + leerfahrtMs - ride.pickupTimestamp) / 60000);
                                hasConflict = true;
                                conflictRideName = `${r.customerName || '?'} (${berlinTime(r.pickupTimestamp)}) вҖ” ${zuSpaetMin} Min zu spГӨt (Leerfahrt ${leerfahrtMin} Min)`;
                                break;
                            }
                        } else {
                            // r ist NACH der neuen Fahrt вҖ” schafft Fahrer es zum nГӨchsten Termin?
                            const newEndMs = ride.pickupTimestamp + rideDurMs + bufferMs;
                            const rideDestLat = ride.destCoords?.lat || ride.destinationLat;
                            const rideDestLon = ride.destCoords?.lon || ride.destinationLon;
                            const rPLat = r.pickupCoords?.lat || r.pickupLat;
                            const rPLon = r.pickupCoords?.lon || r.pickupLon;
                            const leerfahrtMin = quickLeerfahrtMin(rideDestLat, rideDestLon, rPLat, rPLon);
                            const leerfahrtMs = leerfahrtMin * 60000;
                            if (newEndMs + leerfahrtMs > r.pickupTimestamp) {
                                const zuSpaetMin = Math.round((newEndMs + leerfahrtMs - r.pickupTimestamp) / 60000);
                                hasConflict = true;
                                conflictRideName = `${r.customerName || '?'} (${berlinTime(r.pickupTimestamp)}) вҖ” ${zuSpaetMin} Min zu spГӨt (Leerfahrt ${leerfahrtMin} Min)`;
                                break;
                            }
                        }
                    }
                    if (hasConflict) {
                        candidateDebug.push(`  ${vName}: вқҢ Zeitkonflikt: ${conflictRideName}`);
                        continue;
                    }

                    // Leerfahrt fГјr Alternative berechnen (OSRM Smart Routing)
                    const altResult = await estimateVehicleLeerfahrt(
                        vehicleId, ride, allRides, vehiclesData, shiftsData, dateStr, pricingSettings
                    );

                    // рҹҶ• v6.32.0: Score = Leerfahrt + PrioritГӨts-Penalty + Lastverteilung
                    const altPrio = getVehiclePriority(vehicleId);
                    const altRideCount = allRides.filter(r => r.assignedVehicle === vehicleId && r.firebaseId !== ride.firebaseId).length;
                    const altLoadPenalty = altRideCount > avgRidesPerVehicle ? Math.round((altRideCount - avgRidesPerVehicle) * lastverteilungMalus) : 0;
                    const altScore = altResult.durationMin + (altPrio - 1) * priorityAdvantageMin + altLoadPenalty;

                    candidateDebug.push(`  ${vName}: Leerfahrt ${altResult.durationMin}min (${altResult.method}) + Prio ${(altPrio-1)*priorityAdvantageMin} + Last ${altLoadPenalty} = Score ${Math.round(altScore)} ${altScore < bestScore ? 'вң… BESSER' : 'в¬ң schlechter'}`);

                    if (altScore < bestScore) {
                        bestScore = altScore;
                        bestMin = altResult.durationMin;
                        bestKm = altResult.distKm;
                        bestMethod = altResult.method;
                        bestAlt = vehicleId;
                    }
                }

                // рҹ”§ v6.34.0: Detailliertes Debug-Log
                const currVName = (OFFICIAL_VEHICLES[currentVehicle] || {}).name || currentVehicle;
                const bestAltName = bestAlt ? ((OFFICIAL_VEHICLES[bestAlt] || {}).name || bestAlt) : 'keine';
                const rideTimeDbg = berlinTime(ride.pickupTimestamp);
                const rideDateDbg = berlinDate(ride.pickupTimestamp);
                const currScoreDetail = `Leerfahrt ${currentMin}min (${currentResult.method}) + Prio ${(currentPrio-1)*priorityAdvantageMin} + Last ${currentLoadPenalty} = Score ${Math.round(currentScore)}`;

                if (!bestAlt) {
                    debugPhase2Lines.push(`\nрҹ“Ӣ ${rideDateDbg} ${rideTimeDbg} ${ride.customerName || '?'} [${ride.status}]`);
                    debugPhase2Lines.push(`  Aktuell: ${currVName} вҖ” ${currScoreDetail}`);
                    candidateDebug.forEach(l => debugPhase2Lines.push(l));
                    debugPhase2Lines.push(`  вқҢ ERGEBNIS: keine bessere Alternative`);
                    continue;
                }

                // Vorteil = Differenz der Scores (Leerfahrt + PrioritГӨt)
                const vorteilMin = Math.round(currentScore - bestScore);

                if (vorteilMin < minLeerfahrtVorteilMin) {
                    debugPhase2Lines.push(`\nрҹ“Ӣ ${rideDateDbg} ${rideTimeDbg} ${ride.customerName || '?'} [${ride.status}]`);
                    debugPhase2Lines.push(`  Aktuell: ${currVName} вҖ” ${currScoreDetail}`);
                    candidateDebug.forEach(l => debugPhase2Lines.push(l));
                    debugPhase2Lines.push(`  вқҢ ERGEBNIS: Vorteil ${vorteilMin} Min < Mindest ${minLeerfahrtVorteilMin} Min`);
                    continue;
                }

                // рҹ”§ v6.25.4: Nicht umplanen wenn gleiches Ergebnis wie letztes Mal
                // Verhindert Oszillation (AвҶ’BвҶ’AвҶ’B) und doppelte Nachrichten
                if (ride.lastOptimizedTo === bestAlt && ride.lastOptimizedAt && (now - ride.lastOptimizedAt) < 60 * 60000) {
                    const skipMinAgo = Math.round((now - ride.lastOptimizedAt) / 60000);
                    console.log(`   вҸӯпёҸ Skip: ${ride.customerName || '?'} wurde bereits zu ${bestAlt} optimiert (${skipMinAgo} Min her)`);
                    debugPhase2Lines.push(`\nрҹ“Ӣ ${rideDateDbg} ${rideTimeDbg} ${ride.customerName || '?'} [${ride.status}]`);
                    debugPhase2Lines.push(`  Aktuell: ${currVName} вҖ” ${currScoreDetail}`);
                    candidateDebug.forEach(l => debugPhase2Lines.push(l));
                    debugPhase2Lines.push(`  вқҢ ERGEBNIS: Oszillationsschutz вҖ” ${bestAltName} vor ${skipMinAgo} Min`);
                    continue;
                }

                // Erfolgreiche Optimierung вҶ’ auch loggen
                debugPhase2Lines.push(`\nрҹ“Ӣ ${rideDateDbg} ${rideTimeDbg} ${ride.customerName || '?'} [${ride.status}]`);
                debugPhase2Lines.push(`  Aktuell: ${currVName} вҖ” ${currScoreDetail}`);
                candidateDebug.forEach(l => debugPhase2Lines.push(l));
                debugPhase2Lines.push(`  вң… UMPLANUNG: ${currVName} вҶ’ ${bestAltName} (Vorteil: ${vorteilMin} Min)`);

                const altInfo = OFFICIAL_VEHICLES[bestAlt] || {};
                const currInfo = OFFICIAL_VEHICLES[currentVehicle] || {};
                const rideTime = berlinTime(ride.pickupTimestamp);
                const rideDate = berlinDate(ride.pickupTimestamp);
                // Datum als dd.mm. formatieren
                const rideDateParts = rideDate.split('-');
                const rideDateFormatted = rideDateParts.length === 3 ? `${rideDateParts[2]}.${rideDateParts[1]}.` : rideDate;

                console.log(`   рҹҡҖ OPTIMIERUNG: ${ride.customerName || '?'} (${rideDateFormatted} ${rideTime}) | ${currInfo.name} (${currentKm} km, ${currentMin} Min, ${currentResult.method}) вҶ’ ${altInfo.name} (${bestKm} km, ${bestMin} Min, ${bestMethod}) | Vorteil: ${vorteilMin} Min`);

                // vehicleScores fГјr Browser-Anzeige erstellen
                const optimizeScores = {};
                optimizeScores[currentVehicle] = {
                    status: 'available',
                    leerfahrtMin: Math.round(currentMin),
                    leerfahrtVon: currentResult.method,
                    routeMethod: currentResult.method,
                    priorityPenalty: (getVehiclePriority(currentVehicle) - 1) * priorityAdvantageMin,
                    totalScore: Math.round(currentScore)
                };
                optimizeScores[bestAlt] = {
                    status: 'chosen',
                    leerfahrtMin: Math.round(bestMin),
                    leerfahrtVon: bestMethod,
                    routeMethod: bestMethod,
                    priorityPenalty: (getVehiclePriority(bestAlt) - 1) * priorityAdvantageMin,
                    totalScore: Math.round(bestScore)
                };

                // Umplanen in Firebase
                await db.ref(`rides/${ride.firebaseId}`).update({
                    assignedVehicle: bestAlt,
                    vehicleId: bestAlt,
                    vehicle: altInfo.name || bestAlt,
                    vehicleLabel: altInfo.name || bestAlt,
                    vehiclePlate: altInfo.plate || '',
                    assignedVehicleName: altInfo.name || bestAlt,
                    assignedVehiclePlate: altInfo.plate || '',
                    assignedBy: 'cloud-auto-optimize',
                    assignedAt: Date.now(),
                    updatedAt: Date.now(),
                    lastOptimizedAt: Date.now(), // рҹ”§ v6.25.4: Cooldown gegen Duplikat-Nachrichten
                    lastOptimizedTo: bestAlt, // рҹ”§ v6.25.4: Merken wohin optimiert вҶ’ verhindert Oszillation
                    drivingTimeToPickup: Math.round(bestMin),
                    vehicleScores: optimizeScores,
                    replanReason: `Smart-Routing: ${currInfo.name} (${currentKm} km, ${currentMin} Min) вҶ’ ${altInfo.name} (${bestKm} km, ${bestMin} Min), ${vorteilMin} Min kГјrzer`
                });

                // Lokales Array aktualisieren
                ride.assignedVehicle = bestAlt;
                totalOptimized++;

                // рҹ”§ v6.25.4: Detailliertes Log in Firebase (statt Telegram-Spam)
                const currPrioVal = getVehiclePriority(currentVehicle);
                const bestPrioVal = getVehiclePriority(bestAlt);
                const currPenalty = (currPrioVal - 1) * priorityAdvantageMin;
                const bestPenalty = (bestPrioVal - 1) * priorityAdvantageMin;
                try {
                    await db.ref('optimierungsLog').push({
                        timestamp: Date.now(),
                        type: 'cloud-optimize-leerfahrt',
                        rideId: ride.firebaseId,
                        vonVehicle: currInfo.name || currentVehicle,
                        zuVehicle: altInfo.name || bestAlt,
                        vonDistanzKm: currentKm,
                        zuDistanzKm: bestKm,
                        vonDauerMin: currentMin,
                        zuDauerMin: bestMin,
                        vonMethod: currentResult.method,
                        zuMethod: bestMethod,
                        vonPrioritaet: currPrioVal,
                        zuPrioritaet: bestPrioVal,
                        vonMalus: currPenalty,
                        zuMalus: bestPenalty,
                        vonScore: Math.round(currentScore),
                        zuScore: Math.round(bestScore),
                        vorteilMin,
                        echteFahrzeitDiff: Math.round(currentMin - bestMin),
                        kunde: ride.customerName || '',
                        abholung: (ride.pickup || '').substring(0, 50),
                        ziel: (ride.destination || '').substring(0, 50),
                        uhrzeit: rideTime,
                        datum: dateStr,
                        grund: `Smart-Routing: ${vorteilMin} Min kГјrzer`
                    });
                } catch(e) { /* non-critical */ }

                // Telegram an Admins вҖ” kurze Zusammenfassung (Details im Optimierungs-Log)
                try {
                    const msg = `рҹҡҖ *Optimierung*\nрҹ“… ${rideDateFormatted} вҖў ${rideTime}\nрҹ“Ӣ ${ride.customerName || '?'}\nрҹ”„ ${currInfo.name} вҶ’ ${altInfo.name} (${vorteilMin} Min besser)\nрҹ’Ў Details im Optimierungs-Log`;
                    await sendToAllAdmins(msg, 'optimization');
                    await sendToSystemChannel(msg, 'optimization');
                } catch(e) { /* non-critical */ }
            }

            console.log(`вң… Auto-Optimierung abgeschlossen: ${totalReplanned} Konflikt-Umplanung(en), ${totalOptimized} Leerfahrt-Optimierung(en)`);

            // рҹ”§ v6.34.0: Debug Phase 2 per Telegram senden
            // Sende IMMER wenn optimizableRides > 0 und debugOptimierung = true
            // Oder speichere Log immer in Firebase fГјr Analyse
            try {
                // Log immer in Firebase speichern
                if (debugPhase2Lines.length > 0) {
                    await db.ref('optimierungsLog').push({
                        timestamp: Date.now(),
                        type: 'phase2-debug',
                        optimizableCount: optimizableRides.length,
                        optimizedCount: totalOptimized,
                        replannedCount: totalReplanned,
                        minVorteil: minLeerfahrtVorteilMin,
                        prioVorteil: priorityAdvantageMin,
                        details: debugPhase2Lines.join('\n').substring(0, 4000)
                    });
                }
                // Per Telegram senden wenn Flag gesetzt
                const debugSnap3 = await db.ref('settings/debugOptimierung').once('value');
                if (debugSnap3.val() === true) {
                    const p2Header = `рҹ”Қ *Debug: Phase 2 Optimierung*\nрҹ“Ҡ ${optimizableRides.length} Fahrten, ${totalOptimized} optimiert, ${totalReplanned} umgeplant\nвҡҷпёҸ Min-Vorteil: ${minLeerfahrtVorteilMin} Min, Prio-Vorteil: ${priorityAdvantageMin} Min\n`;
                    // Telegram hat 4096 Zeichen Limit вҖ” kГјrzen wenn nГ¶tig
                    let p2Body = debugPhase2Lines.join('\n');
                    if (p2Header.length + p2Body.length > 3900) {
                        p2Body = p2Body.substring(0, 3900 - p2Header.length) + '\n...(gekГјrzt)';
                    }
                    const p2Msg = p2Header + '\n' + (p2Body || '(keine Fahrten geprГјft)');
                    await sendToAllAdmins(p2Msg, 'optimization');
                    await db.ref('settings/debugOptimierung').set(false);
                }
            } catch(e) { console.warn('Debug-Log Fehler:', e.message); }

        } catch (e) {
            console.error('вқҢ Auto-Konflikt-PrГјfung/Optimierung Fehler:', e.message, e.stack);
        }
    }
);

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹ”§ v6.25.4: Homebase aus Schichtplan ermitteln (wie getVehicleHomeForTime in index.html)
// UnterstГјtzt: Split-Schicht (timeRanges), Tagesausnahmen, defaultTimes
// рҹ”§ v6.38.35: Bekannte Standorte mit Koordinaten (fГјr Schichtplan-AuflГ¶sung)
const KNOWN_HOME_LOCATIONS = {
    'bahnhof heringsdorf': { lat: 53.9498, lon: 14.1592 },
    'bahnhof heringsdorf, am bahnhof 17424 heringsdorf': { lat: 53.9498, lon: 14.1592 },
    'am bahnhof 17424 heringsdorf': { lat: 53.9498, lon: 14.1592 },
    'home base patrick': { lat: 53.9659, lon: 14.1523 },
    'im mГјhlenkamp 19': { lat: 53.9659, lon: 14.1523 },
    'im mГјhlenkamp 19, 17424 heringsdorf': { lat: 53.9659, lon: 14.1523 }
};

function resolveHomeLocationToCoords(locationName) {
    if (!locationName) return null;
    const key = locationName.toLowerCase().trim();
    if (KNOWN_HOME_LOCATIONS[key]) return KNOWN_HOME_LOCATIONS[key];
    // Teilwort-Match
    for (const [k, coords] of Object.entries(KNOWN_HOME_LOCATIONS)) {
        if (key.includes(k) || k.includes(key)) return coords;
    }
    return null;
}

function getVehicleHomeCoords(vehicleId, shiftsData, dateStr, timeStr) {
    const vShift = shiftsData[vehicleId];
    if (!vShift) return null;

    const d = new Date(dateStr + 'T00:00:00');
    const dow = d.getDay();
    const dayEntry = vShift[dateStr];
    const defTimes = vShift.defaultTimes || {};

    // 1. Tagesausnahme mit timeRanges (Split-Schicht)
    if (dayEntry && dayEntry.timeRanges && dayEntry.timeRanges.length > 1) {
        for (const range of dayEntry.timeRanges) {
            if (timeStr >= range.startTime && timeStr <= range.endTime) {
                if (range.homeCoords?.lat) return range.homeCoords;
                // рҹ”§ v6.38.35: homeLocation-Text in Koordinaten auflГ¶sen
                const resolved = resolveHomeLocationToCoords(range.homeLocation);
                if (resolved) return resolved;
            }
        }
    }
    // 2. Tagesausnahme direkt
    if (dayEntry && dayEntry.homeCoords?.lat) return dayEntry.homeCoords;
    if (dayEntry && dayEntry.homeLocation) {
        const resolved = resolveHomeLocationToCoords(dayEntry.homeLocation);
        if (resolved) return resolved;
    }
    // 3. defaultTimes mit timeRanges (Split-Schicht)
    if (defTimes[dow] && defTimes[dow].timeRanges && defTimes[dow].timeRanges.length > 1) {
        for (const range of defTimes[dow].timeRanges) {
            if (timeStr >= range.startTime && timeStr <= range.endTime) {
                if (range.homeCoords?.lat) return range.homeCoords;
                const resolved = resolveHomeLocationToCoords(range.homeLocation);
                if (resolved) return resolved;
            }
        }
    }
    // 4. defaultTimes direkt
    if (defTimes[dow] && defTimes[dow].homeCoords?.lat) return defTimes[dow].homeCoords;
    if (defTimes[dow] && defTimes[dow].homeLocation) {
        const resolved = resolveHomeLocationToCoords(defTimes[dow].homeLocation);
        if (resolved) return resolved;
    }

    return null;
}

// рҹ”§ v6.25.4: Smart Routing Leerfahrt-SchГӨtzung via OSRM
// Logik Гјbernommen von autoAssignVehicleToRide + Smart Routing (index.html)
// Berechnet die ECHTE Fahrzeit (Minuten) vom wahrscheinlichen Standort zum Abholort
// Smart Routing: Vergleicht Direkt-Route vs. Гјber-Homebase und nimmt die kГјrzere
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
async function estimateVehicleLeerfahrt(vehicleId, targetRide, allRides, vehiclesData, shiftsData, dateStr, pricingSettings) {
    const pickupLat = targetRide.pickupCoords?.lat || targetRide.pickupLat;
    const pickupLon = targetRide.pickupCoords?.lon || targetRide.pickupLon;
    if (!pickupLat || !pickupLon) return { durationMin: 999, distKm: 999, method: 'no-coords' };

    const returnBufferMin = (pricingSettings && pricingSettings.standortRueckkehrPufferMinuten != null)
        ? pricingSettings.standortRueckkehrPufferMinuten : 30;

    // Abholzeit als HH:MM fГјr Schichtplan-Lookup
    const pickupDate = new Date(targetRide.pickupTimestamp);
    const month = pickupDate.getUTCMonth() + 1;
    const isSummer = month >= 4 && month <= 10;
    const berlinHour = (pickupDate.getUTCHours() + (isSummer ? 2 : 1)) % 24;
    const timeStr = String(berlinHour).padStart(2, '0') + ':' + String(pickupDate.getUTCMinutes()).padStart(2, '0');

    // Homebase aus Schichtplan
    const homeCoords = getVehicleHomeCoords(vehicleId, shiftsData, dateStr, timeStr);
    const homeLat = homeCoords?.lat || null;
    const homeLon = homeCoords?.lon || null;

    // Vorherige Fahrt auf diesem Fahrzeug AM SELBEN TAG suchen
    // рҹ”§ v6.33.6: 'completed' und 'abgeschlossen' ausschlieГҹen!
    // Erledigte Fahrten verfГӨlschen die Leerfahrt-Berechnung
    const vehicleRides = allRides.filter(r => {
        if (r.assignedVehicle !== vehicleId) return false;
        if (r.firebaseId === targetRide.firebaseId) return false;
        if (!r.pickupTimestamp || r.pickupTimestamp >= targetRide.pickupTimestamp) return false;
        if (['deleted','cancelled','storniert','cancelled_pending_driver','completed','abgeschlossen'].includes(r.status)) return false;
        // Nur Fahrten desselben Tages
        const rDateStr = berlinDateGlobal(r.pickupTimestamp);
        return rDateStr === dateStr;
    }).sort((a, b) => b.pickupTimestamp - a.pickupTimestamp);

    // Keine Vorfahrt am selben Tag вҶ’ Homebase oder GPS
    if (vehicleRides.length === 0) {
        if (homeLat && homeLon) {
            const route = await calculateRoute({ lat: homeLat, lon: homeLon }, { lat: pickupLat, lon: pickupLon });
            if (route) return { durationMin: route.duration, distKm: parseFloat(route.distance), method: 'homebase' };
            return { durationMin: gpsDistanceKm(homeLat, homeLon, pickupLat, pickupLon) * 2, distKm: gpsDistanceKm(homeLat, homeLon, pickupLat, pickupLon), method: 'homebase-luftlinie' };
        }
        // GPS-Fallback
        const driver = vehiclesData[vehicleId];
        if (driver?.lat && driver?.lon) {
            const route = await calculateRoute({ lat: driver.lat, lon: driver.lon }, { lat: pickupLat, lon: pickupLon });
            if (route) return { durationMin: route.duration, distKm: parseFloat(route.distance), method: 'gps' };
        }
        return { durationMin: 50, distKm: 25, method: 'fallback' };
    }

    // Vorfahrt vorhanden вҶ’ Smart Routing
    const prevRide = vehicleRides[0];
    const prevDurMs = (prevRide.duration || prevRide.estimatedDuration || 20) * 60000;
    const prevEndTs = prevRide.pickupTimestamp + prevDurMs;
    const gapMinutes = (targetRide.pickupTimestamp - prevEndTs) / 60000;

    const destLat = prevRide.destCoords?.lat || prevRide.destinationLat;
    const destLon = prevRide.destCoords?.lon || prevRide.destinationLon;

    // Entfernung letztes Ziel вҶ’ nГӨchster Abholort (Luftlinie)
    let destToPickupKm = 999;
    if (destLat && destLon) {
        destToPickupKm = gpsDistanceKm(destLat, destLon, pickupLat, pickupLon);
    }

    // рҹҶ• v6.33.8: KLARE REGEL вҖ” Fahrer fГӨhrt IMMER zurГјck zur Basis!
    // Einzige Ausnahme: Anschlussfahrt (< 15 Min Pause + < 5 km entfernt)
    //
    // Standard: Leerfahrt = ab Schichtstandort (Fahrer ist dort)
    // Anschlussfahrt: Leerfahrt = ab Zielort (Fahrer bleibt vor Ort)
    const afZeitfensterMin = (pricingSettings && pricingSettings.anschlussfahrtZeitfensterMin != null)
        ? pricingSettings.anschlussfahrtZeitfensterMin : 15;
    const afRadiusKm = (pricingSettings && pricingSettings.anschlussfahrtRadiusKm != null)
        ? pricingSettings.anschlussfahrtRadiusKm : 5;
    const isAnschlussfahrt = gapMinutes >= 0 && gapMinutes < afZeitfensterMin && destToPickupKm <= afRadiusKm;

    if (isAnschlussfahrt && destLat && destLon) {
        // вң… ANSCHLUSSFAHRT: NГӨchste Fahrt kommt bald + ist in der NГӨhe вҶ’ Fahrer bleibt vor Ort
        console.log(`рҹ”— ${vehicleId}: Anschlussfahrt! ${Math.round(gapMinutes)} Min Pause, ${destToPickupKm.toFixed(1)} km вҶ’ Fahrer bleibt vor Ort`);
        const route = await calculateRoute({ lat: destLat, lon: destLon }, { lat: pickupLat, lon: pickupLon });
        if (route) {
            return { durationMin: route.duration, distKm: parseFloat(route.distance), method: 'anschlussfahrt', isAnschlussfahrt: true };
        }
        return { durationMin: Math.round(destToPickupKm * 2), distKm: destToPickupKm, method: 'anschlussfahrt-luftlinie', isAnschlussfahrt: true };
    }

    // вң… STANDARD: Fahrer ist an der Basis вҶ’ Leerfahrt ab Schichtstandort
    if (homeLat && homeLon) {
        console.log(`рҹҸ  ${vehicleId}: Leerfahrt ab Basis (${Math.round(gapMinutes)} Min Pause, ${destToPickupKm.toFixed(1)} km вҶ’ keine Anschlussfahrt)`);
        const route = await calculateRoute({ lat: homeLat, lon: homeLon }, { lat: pickupLat, lon: pickupLon });
        if (route) {
            return { durationMin: route.duration, distKm: parseFloat(route.distance), method: 'basis', isAnschlussfahrt: false };
        }
        const dist = gpsDistanceKm(homeLat, homeLon, pickupLat, pickupLon);
        return { durationMin: Math.round(dist * 2), distKm: dist, method: 'basis-luftlinie', isAnschlussfahrt: false };
    }

    // Fallback: Keine Basis hinterlegt вҶ’ Direktroute oder GPS
    if (destLat && destLon) {
        const route = await calculateRoute({ lat: destLat, lon: destLon }, { lat: pickupLat, lon: pickupLon });
        if (route) return { durationMin: route.duration, distKm: parseFloat(route.distance), method: 'direkt-fallback', isAnschlussfahrt: false };
    }
    const driver = vehiclesData[vehicleId];
    if (driver?.lat && driver?.lon) {
        const route = await calculateRoute({ lat: driver.lat, lon: driver.lon }, { lat: pickupLat, lon: pickupLon });
        if (route) return { durationMin: route.duration, distKm: parseFloat(route.distance), method: 'gps-fallback', isAnschlussfahrt: false };
    }
    return { durationMin: 50, distKm: 25, method: 'fallback', isAnschlussfahrt: false };
}

// Hilfsfunktion: Alternatives Fahrzeug ohne Zeitkonflikt finden
// рҹ”§ v6.25.4: Firebase-PrioritГӨten + mindestAbstandMin
function findAlternativeVehicle(ride, excludeVehicleId, allRides, shiftsData, dateStr, pricingSettings, vehiclePriorities) {
    const pickupTs = ride.pickupTimestamp;
    const rideDurMs = (ride.duration || ride.estimatedDuration || 20) * 60000;
    const boardingTime = pricingSettings.boardingTime || 3;
    const alightingTime = pricingSettings.alightingTime || 2;
    const bufferMs = (boardingTime + alightingTime) * 60000;
    const mindestAbstandMs = (pricingSettings.mindestAbstandMin || 0) * 60000;

    const berlinTime = (ts) => {
        const d = new Date(ts);
        const month = d.getUTCMonth() + 1;
        const isSummer = month >= 4 && month <= 10;
        const h = (d.getUTCHours() + (isSummer ? 2 : 1)) % 24;
        return String(h).padStart(2, '0') + ':' + String(d.getUTCMinutes()).padStart(2, '0');
    };
    const timeStr = berlinTime(pickupTs);

    // PrioritГӨt aus Firebase, Fallback auf OFFICIAL_VEHICLES
    const getPrio = (vid) => {
        if (vehiclePriorities && vehiclePriorities[vid] !== undefined) return vehiclePriorities[vid];
        return (OFFICIAL_VEHICLES[vid] || {}).priority || 99;
    };

    // Alle Fahrzeuge durchgehen, sortiert nach Firebase-PrioritГӨt
    const candidates = Object.entries(OFFICIAL_VEHICLES)
        .filter(([vid]) => vid !== excludeVehicleId)
        .sort((a, b) => getPrio(a[0]) - getPrio(b[0]));

    for (const [vehicleId, vInfo] of candidates) {
        // KapazitГӨt prГјfen
        if ((vInfo.capacity || 4) < (ride.passengers || 1)) continue;

        // Im Schichtplan?
        if (!isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr)) continue;

        // рҹҶ• v6.26.0: Schichtende-PrГјfung
        const _fRideDurMin = ride.duration || ride.estimatedDuration || 20;
        const _fRideEndMs = ride.pickupTimestamp + _fRideDurMin * 60000;
        const _fRideEndBerlin = new Date(new Date(_fRideEndMs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
        const _fRideEndTimeStr = String(_fRideEndBerlin.getHours()).padStart(2,'0') + ':' + String(_fRideEndBerlin.getMinutes()).padStart(2,'0');
        const _fShiftEnd = getShiftEndTime(vehicleId, shiftsData, dateStr, timeStr);
        if (_fShiftEnd && _fRideEndTimeStr > _fShiftEnd) continue;

        // рҹ”§ v6.26.0: Besetzt-Check вҖ” nicht auf aktive Fahrzeuge umplanen!
        // рҹ”§ v6.34.0: FIX вҖ” 'assigned' entfernt! Nur on_way/picked_up = wirklich unterwegs.
        const vehicleBusy = allRides.some(r =>
            (r.vehicleId === vehicleId || r.assignedVehicle === vehicleId) &&
            (r.status === 'on_way' || r.status === 'picked_up') &&
            r.firebaseId !== ride.firebaseId
        );
        if (vehicleBusy) continue;

        // Zeitkonflikt mit bestehenden Fahrten auf diesem Fahrzeug? (inkl. RГјckfahrt + mindestAbstand)
        // рҹҶ• v6.33.8: RГјckfahrt zur Basis einrechnen! Standardpuffer aus Settings (default 30 Min)
        const rueckfahrtPufferMs = (pricingSettings.standortRueckkehrPufferMinuten || 30) * 60000;
        const hasConflict = allRides.some(r => {
            if (r.firebaseId === ride.firebaseId) return false;
            if (r.assignedVehicle !== vehicleId) return false;
            if (!r.pickupTimestamp) return false;
            if (['deleted','cancelled','storniert','completed'].includes(r.status)) return false;

            const rDurMs = (r.duration || r.estimatedDuration || 20) * 60000;
            // Fahrt belegt = Fahrtdauer + Ein/Aussteigen + RГјckfahrt zur Basis
            const rEnd = r.pickupTimestamp + rDurMs + bufferMs + rueckfahrtPufferMs;
            const newEnd = pickupTs + rideDurMs + bufferMs + rueckfahrtPufferMs;
            return (pickupTs < rEnd + mindestAbstandMs) && (r.pickupTimestamp < newEnd + mindestAbstandMs);
        });

        if (!hasConflict) {
            return vehicleId;
        }
    }

    return null; // Kein freies Fahrzeug gefunden
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// рҹҶ• v6.20.0: SERVER-SEITIGE TELEGRAM-BENACHRICHTIGUNGEN
// Firebase Database Triggers вҖ” funktionieren OHNE offenen Browser!
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// Hilfsfunktion: Berlin-Zeit formatieren
function formatBerlinTime(timestamp) {
    const d = new Date(timestamp || Date.now());
    return d.toLocaleString('de-DE', {
        timeZone: 'Europe/Berlin',
        day: '2-digit', month: '2-digit', year: '2-digit',
        hour: '2-digit', minute: '2-digit', second: '2-digit'
    });
}

